export const fetchGeminiAnalysis = async (prompt: string, isComplex: boolean = false, apiKey?: string): Promise<AnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey: apiKey || process.env.API_KEY || "" });
  const response = await ai.models.generateContent({ model: isComplex ? GEMINI_MODEL_COMPLEX : GEMINI_MODEL_PRIMARY, contents: prompt, config: { tools: [{ googleSearch: {} }] } });
  return { content: response.text || "", timestamp: Date.now(), modelUsed: ModelProvider.GEMINI_INTL, groundingSource: response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((c: any) => ({ uri: c.web?.uri || "", title: c.web?.title || "" })).filter((s: any) => s.uri) || [] };
};

export const parseBrokerageScreenshot = async (base64Image: string, apiKey?: string): Promise<HoldingsSnapshot> => {
  const ai = new GoogleGenAI({ apiKey: apiKey || process.env.API_KEY || "" });
  const response = await ai.models.generateContent({
    model: GEMINI_MODEL_PRIMARY,
    contents: { parts: [{ inlineData: { mimeType: 'image/jpeg', data: base64Image } }, { text: "识别图中所有股票持仓信息。" }] },
    config: { responseMimeType: "application/json", responseSchema: holdingsSnapshotSchema }
  });
  return robustParse(response.text || "{}");
};

export const extractTradingPlan = async (analysisText: string, apiKey?: string): Promise<{ items: PlanItem[], summary: string }> => {
  const ai = new GoogleGenAI({ apiKey: apiKey || process.env.API_KEY || "" });
  const response = await ai.models.generateContent({
    model: GEMINI_MODEL_PRIMARY,
    contents: `请从以下分析中提取结构化【交易计划】。
      [要求]: 
      1. 所有字段（symbol, price_target, reason, summary）必须使用【中文】。
      2. 理由必须简洁有力。
      分析文本: ${analysisText}`,
    config: { responseMimeType: "application/json", responseSchema: tradingPlanSchema }
  });
  const data = robustParse(response.text || "{}");
  return { items: data?.items || [], summary: data?.summary || "" };
};

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { ModelProvider, AnalysisResult, UserSettings, MarketType, HoldingsSnapshot, HoldingItemDetailed, JournalEntry, DailyTradingPlan } from '../types';
import { analyzeWithLLM } from '../services/llmAdapter';
import { parseBrokerageScreenshot, extractTradingPlan } from '../services/geminiService';
import { Upload, Loader2, Save, Download, UploadCloud, History, Trash2, Camera, Edit2, Check, X, TrendingUp, AlertTriangle, Activity, Target, ClipboardList, Calendar, ChevronLeft, ChevronRight, Filter, ListTodo, Search, Clock } from 'lucide-react';

const ITEMS_PER_PAGE_JOURNAL = 5;
const ITEMS_PER_PAGE_PLAN = 3;

export const HoldingsReview: React.FC<{
  currentModel: ModelProvider;
  currentMarket: MarketType;
  settings: UserSettings;
  onOpenSettings?: () => void;
}> = ({ currentModel, currentMarket, settings, onOpenSettings }) => {
  // --- States ---
  const [snapshot, setSnapshot] = useState<HoldingsSnapshot>({
    totalAssets: 0,
    positionRatio: 0,
    date: new Date().toISOString().split('T')[0],
    holdings: []
  });

  const [journal, setJournal] = useState<JournalEntry[]>(() => {
    const saved = localStorage.getItem('qm_journal');
    return saved ? JSON.parse(saved) : [];
  });

  const [tradingPlans, setTradingPlans] = useState<DailyTradingPlan[]>(() => {
    const saved = localStorage.getItem('qm_trading_plans');
    return saved ? JSON.parse(saved) : [];
  });

  const [analysisResult, setAnalysisResult] = useState<AnalysisResult | null>(null);
  const [loading, setLoading] = useState(false);
  const [parsing, setParsing] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // UI Pagination & Filters
  const [journalPage, setJournalPage] = useState(1);
  const [journalDateFilter, setJournalDateFilter] = useState('');
  const [planPage, setPlanPage] = useState(1);
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);
  const [isPlanOpen, setIsPlanOpen] = useState(false);

  const [editingIndex, setEditingIndex] = useState<number | null>(null);
  const [editForm, setEditForm] = useState<HoldingItemDetailed | null>(null);
  const [generatingPlan, setGeneratingPlan] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // --- Derived Data ---
  const filteredJournal = useMemo(() => {
    let result = [...journal];
    if (journalDateFilter) {
      result = result.filter(entry => new Date(entry.timestamp).toISOString().split('T')[0] === journalDateFilter);
    }
    return result;
  }, [journal, journalDateFilter]);

  const totalJournalPages = Math.ceil(filteredJournal.length / ITEMS_PER_PAGE_JOURNAL);
  const currentJournalItems = filteredJournal.slice((journalPage - 1) * ITEMS_PER_PAGE_JOURNAL, journalPage * ITEMS_PER_PAGE_JOURNAL);

  const totalPlanPages = Math.ceil(tradingPlans.length / ITEMS_PER_PAGE_PLAN);
  const currentPlanItems = tradingPlans.slice((planPage - 1) * ITEMS_PER_PAGE_PLAN, planPage * ITEMS_PER_PAGE_PLAN);

  // --- Persistence ---
  useEffect(() => { localStorage.setItem('qm_journal', JSON.stringify(journal)); }, [journal]);
  useEffect(() => { localStorage.setItem('qm_trading_plans', JSON.stringify(tradingPlans)); }, [tradingPlans]);

  // --- Handlers ---
  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setParsing(true);
    setError(null);
    try {
      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64String = (reader.result as string).split(',')[1];
        try {
          const parsedData = await parseBrokerageScreenshot(base64String, settings.geminiKey);
          setSnapshot({ ...parsedData, date: new Date().toISOString().split('T')[0] });
        } catch (err: any) { setError("识别失败，请检查网络或配置。"); }
        finally { setParsing(false); }
      };
      reader.readAsDataURL(file);
    } catch (err) { setParsing(false); setError("读取失败"); }
  };

  const handleAnalyze = async () => {
    if (snapshot.holdings.length === 0) { setError("列表为空"); return; }
    setLoading(true);
    setAnalysisResult(null);
    setError(null);
    try {
      const result = await analyzeWithLLM(currentModel, `请诊断持仓: ${JSON.stringify(snapshot.holdings)}`, true, settings, false, 'day', undefined, currentMarket);
      setAnalysisResult(result);
    } catch (err: any) { setError(err.message); }
    finally { setLoading(false); }
  };

  const handleGeneratePlan = async () => {
    if (!analysisResult) return;
    setGeneratingPlan(true);
    try {
      const { items, summary } = await extractTradingPlan(analysisResult.content, settings.geminiKey);
