  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setParsing(true);
    setError(null);
    try {
      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64String = (reader.result as string).split(',')[1];
        try {
          const parsedData = await parseBrokerageScreenshot(base64String, settings.geminiKey);
          setSnapshot({ ...parsedData, date: new Date().toISOString().split('T')[0] });
        } catch (err: any) { setError("持仓识别失败，请检查 API 配置。"); }
        finally { setParsing(false); }
      };
      reader.readAsDataURL(file);
    } catch (err) { setParsing(false); setError("文件读取失败"); }
  };

  const handleAnalyze = async () => {
    if (snapshot.holdings.length === 0) { setError("请先添加持仓或上传截图"); return; }
    setLoading(true);
    setAnalysisResult(null);
    setError(null);
    try {
      const holdingsSummary = snapshot.holdings.map(h => `${h.name}(${h.code}): 成本${h.costPrice}, 现价${h.currentPrice}`).join('; ');
