             const cleanText = trimmed.replace(/^[*-\s]*/, '');
             return (
               <div key={i} className="flex gap-3 pl-2 py-1">
                 <span className="text-blue-500 font-bold mt-0.5 shrink-0">●</span>
                 <p className="flex-1" dangerouslySetInnerHTML={{ __html: formatLine(cleanText) }} />
               </div>
             );
          }

          return <p key={i} className="pl-1" dangerouslySetInnerHTML={{ __html: formatLine(trimmed) }} />;
        })}
      </div>
    );
  };

  const formatLine = (text: string) => {
    return text.replace(/\*\*(.*?)\*\*/g, '<strong class="text-slate-900 font-bold">$1</strong>');
  };

  return (
    <div className="space-y-6 animate-fade-in pb-20">
      {/* --- Control Center --- */}
      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-8">
