                       </div>
                       <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                          {plan.items.map(item => (
                            <div key={item.id} className="bg-slate-900/60 p-6 rounded-3xl border border-slate-700/50 hover:border-emerald-500/50 transition-all">
                               <div className="flex justify-between items-start mb-4">
