                <button disabled={planPage === 1} onClick={() => setPlanPage(p => p - 1)} className="w-12 h-12 flex items-center justify-center rounded-2xl bg-slate-800 hover:bg-slate-700 disabled:opacity-10 transition-all border border-slate-700">
