                    <input type="date" value={journalDateFilter} onChange={e => {setJournalDateFilter(e.target.value); setJournalPage(1);}} className="text-xs bg-transparent border-none focus:ring-0 text-slate-600" />
                    {journalDateFilter && <X className="w-4 h-4 text-slate-300 cursor-pointer" onClick={() => setJournalDateFilter('')} />}
                 </div>
                 <div className="flex gap-2">
                    <button onClick={() => importInputRef.current?.click()} className="text-[10px] font-black uppercase tracking-widest px-3 py-2 bg-white border rounded-lg hover:text-blue-600 transition-colors">Import JSON</button>
                    <button onClick={exportJournalJSON} className="text-[10px] font-black uppercase tracking-widest px-3 py-2 bg-white border rounded-lg hover:text-blue-600 transition-colors">Export JSON</button>
                    <input type="file" ref={importInputRef} className="hidden" accept=".json" onChange={importJournalJSON} />
                 </div>
              </div>
            </div>

            <div className="space-y-3">
              {currentJournalItems.length === 0 ? (
                <div className="text-center py-16 text-slate-400 text-sm italic border border-dashed rounded-3xl border-slate-300">暂无符合条件的记录</div>
              ) : (
                currentJournalItems.map(entry => (
                  <div key={entry.id} onClick={() => { setSnapshot(entry.snapshot); setAnalysisResult(entry.analysis); setIsHistoryOpen(false); }} className="p-5 bg-white rounded-2xl border border-slate-200 hover:border-blue-400 cursor-pointer transition-all flex justify-between items-center group shadow-sm">
                    <div className="flex items-center gap-5">
                      <div className="w-12 h-12 rounded-xl bg-blue-50 flex items-center justify-center text-blue-600 group-hover:bg-blue-600 group-hover:text-white transition-all"><Calendar className="w-6 h-6" /></div>
                      <div>
                        <div className="text-base font-black text-slate-800">{new Date(entry.timestamp).toLocaleString('zh-CN')}</div>
                        <div className="text-xs text-slate-400 font-bold uppercase mt-1 tracking-wider">资产: ¥{entry.snapshot.totalAssets.toLocaleString()} | {entry.snapshot.holdings.length}个活跃头寸</div>
                      </div>
                    </div>
                    <ChevronRight className="w-5 h-5 text-slate-200 group-hover:text-blue-500 transition-all" />
                  </div>
                ))
              )}
            </div>

            {totalJournalPages > 1 && (
              <div className="flex items-center justify-center gap-8 mt-10">
                <button disabled={journalPage === 1} onClick={() => setJournalPage(p => p - 1)} className="w-10 h-10 flex items-center justify-center rounded-xl border bg-white disabled:opacity-30"><ChevronLeft className="w-5 h-5" /></button>
                <span className="text-xs font-black text-slate-400 tracking-[0.3em]">{journalPage} / {totalJournalPages}</span>
                <button disabled={journalPage === totalJournalPages} onClick={() => setJournalPage(p => p + 1)} className="w-10 h-10 flex items-center justify-center rounded-xl border bg-white disabled:opacity-30"><ChevronRight className="w-5 h-5" /></button>
              </div>
            )}
          </div>
        )}

        {/* --- Snapshot Input (Preserved) --- */}
        <div className="overflow-hidden rounded-3xl border border-slate-200 shadow-sm mb-8 bg-slate-50/20">
          <div className="bg-slate-50/50 px-8 py-5 border-b flex justify-between items-center">
             <div className="flex gap-10">
                <div className="group">
                  <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-1 group-hover:text-blue-600 transition-colors">Account Assets (CNY)</span>
                  <input type="number" value={snapshot.totalAssets} onChange={e => setSnapshot({...snapshot, totalAssets: Number(e.target.value)})} className="bg-transparent text-2xl font-black text-slate-800 w-40 outline-none border-b-2 border-dashed border-slate-200 focus:border-blue-500 transition-all" />
                </div>
                <div className="group">
                  <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-1 group-hover:text-blue-600 transition-colors">Exposure (%)</span>
                  <div className="flex items-center gap-1">
                    <input type="number" value={snapshot.positionRatio || 0} onChange={e => setSnapshot({...snapshot, positionRatio: Number(e.target.value)})} className="bg-transparent text-2xl font-black text-slate-800 w-20 outline-none border-b-2 border-dashed border-slate-200 focus:border-blue-500 transition-all" />
                    <span className="text-slate-400 font-black">%</span>
                  </div>
                </div>
             </div>
             <button onClick={() => setSnapshot({...snapshot, holdings: [...snapshot.holdings, { name: "新标的", code: "000000", volume: 0, costPrice: 0, currentPrice: 0, profit: 0, profitRate: "0%", marketValue: 0 }]})} className="text-xs font-black text-blue-600 bg-blue-50 px-5 py-2.5 rounded-xl hover:bg-blue-100 transition-colors border border-blue-100 uppercase tracking-widest">Add Item</button>
          </div>
          <table className="w-full text-sm">
            <thead className="bg-slate-50 text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] border-b">
              <tr>
                <th className="px-8 py-5 text-left">标的与代码</th>
                <th className="px-8 py-5 text-left">持仓数量 / 成本</th>
                <th className="px-8 py-5 text-left">当前市况 / 盈亏</th>
                <th className="px-8 py-5 text-right">操作</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 bg-white">
              {snapshot.holdings.map((item, idx) => (
                <tr key={idx} className="hover:bg-slate-50/50 transition-colors group">
                  <td className="px-8 py-5">
                    <div className="font-black text-slate-800 text-base">{item.name}</div>
                    <div className="text-[10px] font-black font-mono text-slate-400 mt-0.5 tracking-wider">{item.code}</div>
                  </td>
                  <td className="px-8 py-5">
                    <div className="text-slate-600 font-bold">{item.volume.toLocaleString()} 股</div>
                    <div className="text-[10px] text-slate-400 font-black uppercase mt-1 tracking-tighter">Cost @ ¥{item.costPrice}</div>
                  </td>
                  <td className="px-8 py-5">
                    <div className="font-black text-slate-800">¥{item.currentPrice}</div>
                    <div className={`text-[10px] font-black uppercase mt-1 tracking-widest ${item.profit >= 0 ? 'text-rose-500' : 'text-emerald-500'}`}>
                      {item.profitRate} (¥{item.profit.toLocaleString()})
                    </div>
                  </td>
                  <td className="px-8 py-5 text-right">
                    <button onClick={() => setSnapshot({...snapshot, holdings: snapshot.holdings.filter((_, i) => i !== idx)})} className="p-2 text-slate-300 hover:text-rose-500 opacity-0 group-hover:opacity-100 transition-all active:scale-90">
                      <Trash2 className="w-5 h-5" />
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        <div className="flex justify-end">
          <button onClick={handleAnalyze} disabled={loading || snapshot.holdings.length === 0} className="flex items-center gap-3 px-10 py-4 bg-slate-900 hover:bg-slate-800 text-white rounded-2xl font-black shadow-2xl shadow-slate-200 transition-all active:scale-95 disabled:opacity-50">
            {loading ? <Loader2 className="w-6 h-6 animate-spin" /> : <TrendingUp className="w-6 h-6" />}
            {loading ? 'AI 量化深度引擎分析中...' : '生成智能复盘报告'}
          </button>
        </div>
      </div>

      {/* --- Analysis Report Section (Optimized Display) --- */}
      {analysisResult && (
        <div className="bg-white rounded-[3rem] shadow-sm border border-slate-200 overflow-hidden animate-slide-up">
          <div className="bg-slate-50 px-10 py-8 border-b flex justify-between items-center">
            <h3 className="font-black text-slate-900 flex items-center gap-4 text-xl">
              <div className="p-3 bg-blue-100 rounded-2xl shadow-sm"><Activity className="w-6 h-6 text-blue-600" /></div>
              深度量化复盘诊断报告
            </h3>
            <div className="flex gap-3">
              <button onClick={handleGeneratePlan} disabled={generatingPlan} className="text-xs font-black bg-emerald-600 text-white px-6 py-3 rounded-xl hover:bg-emerald-700 flex items-center gap-2 shadow-lg shadow-emerald-100 disabled:opacity-50 transition-all active:scale-95 uppercase tracking-widest">
                {generatingPlan ? <Loader2 className="w-4 h-4 animate-spin" /> : <ListTodo className="w-4 h-4" />}
