              </button>
              <button onClick={saveToJournal} className="text-xs font-black bg-white border border-slate-200 text-slate-600 px-6 py-3 rounded-xl hover:bg-slate-50 flex items-center gap-2 transition-all active:scale-95 uppercase tracking-widest">
                <Save className="w-4 h-4" /> 存档至历史库
              </button>
