      {/* --- Trading Execution Plans (With Export & Pagination) --- */}
      {isPlanOpen && (
        <div className="mt-12 bg-slate-900 text-white rounded-[3.5rem] p-12 shadow-3xl animate-slide-up relative overflow-hidden">
           <div className="absolute top-0 right-0 w-80 h-80 bg-emerald-500/10 blur-[120px] pointer-events-none" />
           <div className="absolute bottom-0 left-0 w-80 h-80 bg-blue-500/10 blur-[120px] pointer-events-none" />

           <div className="flex justify-between items-center mb-12 relative z-10">
              <h3 className="text-3xl font-black flex items-center gap-5">
                <div className="p-4 bg-emerald-500 rounded-3xl shadow-[0_0_30px_rgba(16,185,129,0.3)]"><ListTodo className="w-10 h-10 text-white" /></div>
                次日交易指令执行库
              </h3>
              <div className="flex items-center gap-4">
                 <div className="text-[10px] font-black text-slate-500 uppercase tracking-widest bg-slate-800 px-5 py-2.5 rounded-full border border-slate-700">Total Archive: {tradingPlans.length} Sets</div>
              </div>
           </div>

           <div className="space-y-12 relative z-10">
              {currentPlanItems.length === 0 ? (
                <div className="text-center py-24 text-slate-700 font-black uppercase tracking-[0.5em] border-2 border-dashed border-slate-800 rounded-[3rem]">No Active Strategy</div>
