import React, { useState, useEffect, useRef, useMemo } from 'react';
import { ModelProvider, AnalysisResult, UserSettings, MarketType, HoldingsSnapshot, HoldingItemDetailed, JournalEntry, DailyTradingPlan, PlanItem, PeriodicReviewData } from '../types';
import { analyzeWithLLM } from '../services/llmAdapter';
import { parseBrokerageScreenshot, extractTradingPlan, fetchPeriodicReview } from '../services/geminiService';
import { Upload, Loader2, Save, Download, UploadCloud, History, Trash2, Camera, Check, X, TrendingUp, Activity, Target, Calendar, ChevronLeft, ChevronRight, Filter, ListTodo, Clock, FileText, FileDown, CheckCircle2, Square, CheckSquare } from 'lucide-react';

const ITEMS_PER_PAGE_JOURNAL = 5;
const ITEMS_PER_PAGE_PLAN = 3;

export const HoldingsReview: React.FC<{
  currentModel: ModelProvider;
  currentMarket: MarketType;
  settings: UserSettings;
  onOpenSettings?: () => void;
}> = ({ currentModel, currentMarket, settings, onOpenSettings }) => {
  // --- States ---
  const [snapshot, setSnapshot] = useState<HoldingsSnapshot>({
    totalAssets: 0,
    positionRatio: 0,
    date: new Date().toISOString().split('T')[0],
    holdings: []
  });

  const [journal, setJournal] = useState<JournalEntry[]>(() => {
    const saved = localStorage.getItem('qm_journal');
    return saved ? JSON.parse(saved) : [];
  });

  const [tradingPlans, setTradingPlans] = useState<DailyTradingPlan[]>(() => {
    const saved = localStorage.getItem('qm_trading_plans');
    return saved ? JSON.parse(saved) : [];
  });

  const [analysisResult, setAnalysisResult] = useState<AnalysisResult | null>(null);
  const [loading, setLoading] = useState(false);
  const [parsing, setParsing] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const [journalPage, setJournalPage] = useState(1);
  const [journalDateFilter, setJournalDateFilter] = useState('');
  const [planPage, setPlanPage] = useState(1);
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);
  const [isPlanOpen, setIsPlanOpen] = useState(false);

  const [generatingPlan, setGeneratingPlan] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const importInputRef = useRef<HTMLInputElement>(null);

  // --- Persistence ---
  useEffect(() => { localStorage.setItem('qm_journal', JSON.stringify(journal)); }, [journal]);
  useEffect(() => { localStorage.setItem('qm_trading_plans', JSON.stringify(tradingPlans)); }, [tradingPlans]);

  // --- Derived Data ---
  const filteredJournal = useMemo(() => {
    let result = [...journal];
    if (journalDateFilter) {
      result = result.filter(entry => new Date(entry.timestamp).toISOString().split('T')[0] === journalDateFilter);
    }
    return result;
  }, [journal, journalDateFilter]);

  const totalJournalPages = Math.ceil(filteredJournal.length / ITEMS_PER_PAGE_JOURNAL);
  const currentJournalItems = filteredJournal.slice((journalPage - 1) * ITEMS_PER_PAGE_JOURNAL, journalPage * ITEMS_PER_PAGE_JOURNAL);

  const totalPlanPages = Math.ceil(tradingPlans.length / ITEMS_PER_PAGE_PLAN);
  const currentPlanItems = tradingPlans.slice((planPage - 1) * ITEMS_PER_PAGE_PLAN, planPage * ITEMS_PER_PAGE_PLAN);

  // --- Handlers ---
  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setParsing(true);
    setError(null);
    try {
      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64String = (reader.result as string).split(',')[1];
        try {
          const parsedData = await parseBrokerageScreenshot(base64String, settings.geminiKey);
          setSnapshot({ ...parsedData, date: new Date().toISOString().split('T')[0] });
        } catch (err: any) { setError("截图解析失败"); }
        finally { setParsing(false); }
      };
      reader.readAsDataURL(file);
    } catch (err) { setParsing(false); }
  };

  const handleAnalyze = async () => {
    if (snapshot.holdings.length === 0) { setError("持仓列表为空"); return; }
    setLoading(true);
    setAnalysisResult(null);
    setError(null);
    try {
      const prompt = `请深度复盘我的 A 股持仓：${JSON.stringify(snapshot.holdings)}。资产：${snapshot.totalAssets}。
      要求：使用 Markdown ## 标题分段。重点词汇加粗。提供具体的止盈止损建议。`;
      const result = await analyzeWithLLM(currentModel, prompt, true, settings, false, 'day', undefined, currentMarket);
      setAnalysisResult(result);
    } catch (err: any) { setError(err.message); }
    finally { setLoading(false); }
  };

  const handleGeneratePlan = async () => {
    if (!analysisResult) return;
    setGeneratingPlan(true);
    try {
      const { items, summary } = await extractTradingPlan(analysisResult.content, settings.geminiKey);
      const newPlan: DailyTradingPlan = {
        id: crypto.randomUUID(),
        target_date: new Date(Date.now() + 86400000).toISOString().split('T')[0],
        created_at: Date.now(),
        items: items.map(it => ({...it, status: 'pending'})),
        strategy_summary: summary
      };
      setTradingPlans(prev => [newPlan, ...prev]);
      setPlanPage(1);
      setIsPlanOpen(true);
    } catch (err: any) { setError("生成失败"); }
    finally { setGeneratingPlan(false); }
  };

  const saveToJournal = () => {
    if (!analysisResult) return;
    const newEntry: JournalEntry = {
      id: crypto.randomUUID(),
      timestamp: Date.now(),
      snapshot: { ...snapshot },
      analysis: analysisResult
    };
    setJournal(prev => [newEntry, ...prev]);
    alert("已存档");
  };

  const toggleItemStatus = (planId: string, itemId: string) => {
    setTradingPlans(prev => prev.map(plan => {
      if (plan.id === planId) {
        return {
          ...plan,
          items: plan.items.map(item => {
            if (item.id === itemId) {
              return { ...item, status: item.status === 'completed' ? 'pending' : 'completed' };
            }
            return item;
          })
        };
      }
      return plan;
    }));
  };

  // --- Export Logic ---
  const exportPlanMD = (plan: DailyTradingPlan) => {
    let md = `# 交易执行日志 (${plan.target_date})\n\n核心策略: ${plan.strategy_summary}\n\n`;
    md += `| 标的 | 动作 | 目标价 | 理由 | 状态 |\n| :--- | :--- | :--- | :--- | :--- |\n`;
    plan.items.forEach(item => {
      md += `| ${item.symbol} | ${item.action} | ${item.price_target} | ${item.reason} | ${item.status === 'completed' ? '已执行' : '待处理'} |\n`;
    });
    const blob = new Blob([md], { type: 'text/markdown' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a'); a.href = url; a.download = `Plan_${plan.target_date}.md`; a.click();
  };

  const deletePlan = (id: string) => { setTradingPlans(prev => prev.filter(p => p.id !== id)); };

  // --- Render Helpers ---
  const renderAnalysisReport = (content: string) => {
    const sections = content.split(/^#+\s+/gm).filter(Boolean);
    return (
      <div className="space-y-6">
        {sections.map((sec, idx) => {
          const lines = sec.trim().split('\n');
          const title = lines[0].trim();
          const body = lines.slice(1).join('\n').trim();
          return (
            <div key={idx} className="bg-white rounded-2xl border border-slate-200 p-6">
              <h3 className="text-lg font-bold text-slate-800 mb-4 flex items-center gap-2">
                <div className="w-1 h-4 bg-blue-600 rounded-full" /> {title}
              </h3>
              <div className="space-y-2">
                {body.split('\n').map((line, i) => {
                   if (!line.trim()) return null;
                   let formatted = line.replace(/\*\*(.*?)\*\*/g, '<strong class="text-slate-900 font-bold">$1</strong>');
                   const up = /(买入|加仓|突破|支撑)/g;
                   const down = /(卖出|减仓|跌破|压力)/g;
                   formatted = formatted.replace(up, '<span class="text-rose-600 font-bold">$1</span>');
                   formatted = formatted.replace(down, '<span class="text-emerald-600 font-bold">$1</span>');
                   return <p key={i} className="text-sm text-slate-600 leading-relaxed" dangerouslySetInnerHTML={{ __html: formatted }} />;
                })}
              </div>
            </div>
          );
        })}
      </div>
    );
  };

  return (
    <div className="space-y-6 animate-fade-in pb-20">
      {/* Dashboard */}
      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-8">
          <div>
            <h2 className="text-2xl font-bold text-slate-800 flex items-center gap-2 tracking-tight">
              <UploadCloud className="w-6 h-6 text-blue-600" /> 持仓诊断中心
            </h2>
            <p className="text-slate-400 text-xs mt-1 uppercase tracking-widest font-bold">Portfolio Diagnostic Archive</p>
          </div>
          <div className="flex gap-2">
            <button onClick={() => setIsPlanOpen(!isPlanOpen)} className="px-4 py-2 text-sm font-bold text-slate-600 bg-slate-50 hover:bg-slate-100 rounded-xl border border-slate-200 transition-all flex items-center gap-2">
              <ListTodo className="w-4 h-4" /> 交易指令库
            </button>
            <button onClick={() => setIsHistoryOpen(!isHistoryOpen)} className="px-4 py-2 text-sm font-bold text-slate-600 bg-slate-50 hover:bg-slate-100 rounded-xl border border-slate-200 transition-all flex items-center gap-2">
              <History className="w-4 h-4" /> 复盘历史
            </button>
            <button onClick={() => fileInputRef.current?.click()} className="px-5 py-2 bg-blue-600 hover:bg-blue-700 text-white rounded-xl text-sm font-bold shadow-sm transition-all flex items-center gap-2">
              {parsing ? <Loader2 className="w-4 h-4 animate-spin" /> : <Camera className="w-4 h-4" />} {parsing ? '解析中' : '上传持仓'}
            </button>
            <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleImageUpload} />
          </div>
        </div>

        {/* History Drawer */}
        {isHistoryOpen && (
          <div className="mb-8 p-6 bg-slate-50 rounded-2xl border border-slate-200 animate-slide-down">
            <div className="flex justify-between items-center mb-4">
              <span className="text-xs font-bold text-slate-400 uppercase tracking-widest">Archive History</span>
              <div className="flex gap-2">
                <input type="date" value={journalDateFilter} onChange={e => setJournalDateFilter(e.target.value)} className="text-xs border border-slate-200 rounded-lg px-2 py-1 outline-none" />
                <button onClick={() => setJournalDateFilter('')} className="text-xs font-bold text-slate-400 hover:text-slate-600 px-2">Clear</button>
              </div>
            </div>
            <div className="space-y-2">
              {currentJournalItems.length === 0 ? <p className="text-center py-8 text-slate-300 text-sm">暂无记录</p> : 
                currentJournalItems.map(entry => (
                  <div key={entry.id} onClick={() => {setSnapshot(entry.snapshot); setAnalysisResult(entry.analysis); setIsHistoryOpen(false);}} className="p-3 bg-white rounded-xl border border-slate-100 hover:border-blue-400 cursor-pointer flex justify-between items-center transition-all group">
                    <div className="flex items-center gap-3">
                      <Calendar className="w-4 h-4 text-slate-300 group-hover:text-blue-500" />
                      <span className="text-sm font-bold text-slate-700">{new Date(entry.timestamp).toLocaleString()}</span>
                    </div>
                    <ChevronRight className="w-4 h-4 text-slate-200 group-hover:text-blue-400" />
                  </div>
                ))
              }
            </div>
          </div>
        )}

        {/* Table View */}
        <div className="overflow-hidden rounded-xl border border-slate-200 mb-6 bg-white">
           <div className="bg-slate-50 px-6 py-4 border-b flex justify-between items-center">
              <div className="flex gap-8">
                 <div>
                    <span className="text-[10px] font-bold text-slate-400 uppercase block mb-0.5">Total Assets</span>
                    <input type="number" value={snapshot.totalAssets} onChange={e => setSnapshot({...snapshot, totalAssets: Number(e.target.value)})} className="bg-transparent text-lg font-bold text-slate-800 w-32 border-b border-dashed border-slate-300 outline-none focus:border-blue-500" />
                 </div>
                 <div>
                    <span className="text-[10px] font-bold text-slate-400 uppercase block mb-0.5">Ratio (%)</span>
                    <input type="number" value={snapshot.positionRatio || 0} onChange={e => setSnapshot({...snapshot, positionRatio: Number(e.target.value)})} className="bg-transparent text-lg font-bold text-slate-800 w-16 border-b border-dashed border-slate-300 outline-none focus:border-blue-500" />
                 </div>
              </div>
              <button onClick={() => setSnapshot({...snapshot, holdings: [...snapshot.holdings, { name: "新持仓", code: "000000", volume: 0, costPrice: 0, currentPrice: 0, profit: 0, profitRate: "0%", marketValue: 0 }]})} className="text-xs font-bold text-blue-600 px-3 py-1.5 rounded-lg hover:bg-blue-50 transition-colors uppercase">Add Row</button>
           </div>
           <table className="w-full text-sm">
             <thead className="bg-slate-50/50 text-[10px] font-bold text-slate-400 uppercase border-b">
               <tr><th className="px-6 py-3 text-left">标的代码</th><th className="px-6 py-3 text-left">成本/数量</th><th className="px-6 py-3 text-left">浮动盈亏</th><th className="px-6 py-3 text-right">管理</th></tr>
             </thead>
             <tbody className="divide-y divide-slate-100">
               {snapshot.holdings.map((item, idx) => (
                 <tr key={idx} className="hover:bg-slate-50/30 group">
                   <td className="px-6 py-3"><div className="font-bold text-slate-800">{item.name}</div><div className="text-[10px] font-mono text-slate-400">{item.code}</div></td>
                   <td className="px-6 py-3"><div className="text-slate-600 font-bold">{item.volume}</div><div className="text-xs text-slate-400">@ {item.costPrice}</div></td>
                   <td className="px-6 py-3"><div className={`font-bold ${item.profit >= 0 ? 'text-rose-500' : 'text-emerald-500'}`}>{item.profitRate}</div><div className="text-[10px] text-slate-400">¥{item.profit.toLocaleString()}</div></td>
                   <td className="px-6 py-3 text-right"><button onClick={() => setSnapshot({...snapshot, holdings: snapshot.holdings.filter((_, i) => i !== idx)})} className="p-1.5 text-slate-300 hover:text-rose-500 opacity-0 group-hover:opacity-100 transition-all"><Trash2 className="w-4 h-4" /></button></td>
                 </tr>
               ))}
             </tbody>
           </table>
        </div>

        <div className="flex justify-end">
          <button onClick={handleAnalyze} disabled={loading || snapshot.holdings.length === 0} className="px-8 py-3 bg-slate-900 hover:bg-slate-800 text-white rounded-xl text-sm font-bold shadow-sm transition-all active:scale-95 disabled:opacity-50 flex items-center gap-2">
            {loading ? <Loader2 className="w-4 h-4 animate-spin" /> : <TrendingUp className="w-4 h-4" />} {loading ? '分析中...' : '生成复盘报告'}
          </button>
        </div>
      </div>

      {/* Reports & Logs */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 items-start">
        {/* Left: Analysis Report */}
        {analysisResult && (
          <div className="space-y-6">
            <div className="bg-slate-100/50 rounded-2xl p-4 flex justify-between items-center border border-slate-200">
               <h3 className="text-sm font-bold text-slate-800 flex items-center gap-2 uppercase tracking-widest"><Activity className="w-4 h-4 text-blue-600" /> 复盘诊断报告</h3>
               <div className="flex gap-2">
                  <button onClick={handleGeneratePlan} disabled={generatingPlan} className="text-[10px] font-bold bg-blue-600 text-white px-3 py-1.5 rounded-lg hover:bg-blue-700 disabled:opacity-50 transition-all">生成执行指令</button>
                  <button onClick={saveToJournal} className="text-[10px] font-bold bg-white text-slate-600 border border-slate-200 px-3 py-1.5 rounded-lg hover:bg-slate-50 transition-all">存入历史</button>
               </div>
            </div>
            {renderAnalysisReport(analysisResult.content)}
          </div>
        )}

        {/* Right: Trading Execution Plan (Action Log Style) */}
        {isPlanOpen && (
          <div className="space-y-6 animate-slide-up">
            <div className="bg-slate-100/50 rounded-2xl p-4 flex justify-between items-center border border-slate-200">
               <h3 className="text-sm font-bold text-slate-800 flex items-center gap-2 uppercase tracking-widest"><ListTodo className="w-4 h-4 text-emerald-600" /> 次日交易操作日志</h3>
               <div className="text-[10px] font-bold text-slate-400">Total Archive: {tradingPlans.length}</div>
            </div>

            <div className="space-y-4">
              {currentPlanItems.length === 0 ? <div className="p-12 text-center text-slate-300 italic border-2 border-dashed rounded-3xl">暂无计划</div> : 
                currentPlanItems.map(plan => (
                  <div key={plan.id} className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm">
                    <div className="bg-slate-50 px-6 py-3 flex justify-between items-center border-b">
                       <span className="text-sm font-bold text-slate-800">{plan.target_date} 操作核心</span>
                       <div className="flex gap-2">
                          <button onClick={() => exportPlanMD(plan)} className="text-[10px] font-bold text-slate-400 hover:text-blue-600 flex items-center gap-1 uppercase tracking-widest"><FileText className="w-3.5 h-3.5" /> Export</button>
                          <button onClick={() => deletePlan(plan.id)} className="text-[10px] font-bold text-slate-400 hover:text-rose-500 uppercase tracking-widest">Delete</button>
                       </div>
                    </div>
                    <div className="p-6">
                       <p className="text-sm text-slate-500 italic mb-6 leading-relaxed bg-slate-50 p-4 rounded-xl border border-slate-100 border-l-4 border-emerald-400">"{plan.strategy_summary}"</p>
                       <div className="space-y-2">
                          {plan.items.map(item => (
                            <div key={item.id} className={`flex items-start gap-4 p-4 rounded-xl border transition-all ${item.status === 'completed' ? 'bg-slate-50 border-slate-100 opacity-60' : 'bg-white border-slate-100 hover:border-emerald-200 hover:bg-emerald-50/20'}`}>
                               <button onClick={() => toggleItemStatus(plan.id, item.id)} className={`mt-1 shrink-0 ${item.status === 'completed' ? 'text-emerald-500' : 'text-slate-300 hover:text-emerald-400'}`}>
                                  {item.status === 'completed' ? <CheckSquare className="w-5 h-5" /> : <Square className="w-5 h-5" />}
                               </button>
                               <div className="flex-1">
                                  <div className="flex justify-between items-center mb-1">
                                     <div className="flex items-center gap-2">
                                        <span className="font-bold text-slate-800 text-base">{item.symbol}</span>
                                        <span className={`text-[10px] font-bold px-2 py-0.5 rounded uppercase tracking-tighter ${item.action === 'buy' ? 'bg-rose-50 text-rose-500' : item.action === 'sell' ? 'bg-emerald-50 text-emerald-500' : 'bg-slate-100 text-slate-500'}`}>
                                           {item.action === 'buy' ? '买入' : item.action === 'sell' ? '卖出' : '持股'}
                                        </span>
                                     </div>
                                     <div className="text-sm font-bold text-slate-800">¥ {item.price_target || '--'}</div>
                                  </div>
                                  <p className="text-xs text-slate-500 leading-relaxed italic">{item.reason}</p>
                               </div>
                            </div>
                          ))}
                       </div>
                    </div>
                  </div>
                ))
              }
            </div>

            {/* Simple Pagination */}
            {totalPlanPages > 1 && (
              <div className="flex items-center justify-center gap-6 mt-6">
                 <button disabled={planPage === 1} onClick={() => setPlanPage(p => p - 1)} className="p-2 text-slate-400 hover:text-blue-600 disabled:opacity-20"><ChevronLeft /></button>
                 <span className="text-[10px] font-bold text-slate-400 tracking-widest">{planPage} / {totalPlanPages}</span>
                 <button disabled={planPage === totalPlanPages} onClick={() => setPlanPage(p => p + 1)} className="p-2 text-slate-400 hover:text-blue-600 disabled:opacity-20"><ChevronRight /></button>
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { ModelProvider, AnalysisResult, UserSettings, MarketType, HoldingsSnapshot, HoldingItemDetailed, JournalEntry, DailyTradingPlan, PlanItem, PeriodicReviewData } from '../types';
import { analyzeWithLLM } from '../services/llmAdapter';
import { parseBrokerageScreenshot, extractTradingPlan, fetchPeriodicReview } from '../services/geminiService';
import { Upload, Loader2, Save, Download, UploadCloud, History, Trash2, Camera, Check, X, TrendingUp, Activity, Target, Calendar, ChevronLeft, ChevronRight, Filter, ListTodo, Clock, FileText, FileDown, CheckCircle2, Square, CheckSquare, AlertCircle, ShieldCheck, Zap } from 'lucide-react';

const ITEMS_PER_PAGE_JOURNAL = 5;
const ITEMS_PER_PAGE_PLAN = 3;

export const HoldingsReview: React.FC<{
  currentModel: ModelProvider;
  currentMarket: MarketType;
  settings: UserSettings;
  onOpenSettings?: () => void;
}> = ({ currentModel, currentMarket, settings, onOpenSettings }) => {
  // --- States ---
  const [snapshot, setSnapshot] = useState<HoldingsSnapshot>({
    totalAssets: 0,
    positionRatio: 0,
    date: new Date().toISOString().split('T')[0],
    holdings: []
  });

  const [journal, setJournal] = useState<JournalEntry[]>(() => {
    const saved = localStorage.getItem('qm_journal');
    return saved ? JSON.parse(saved) : [];
  });

  const [tradingPlans, setTradingPlans] = useState<DailyTradingPlan[]>(() => {
    const saved = localStorage.getItem('qm_trading_plans');
    return saved ? JSON.parse(saved) : [];
  });

  const [analysisResult, setAnalysisResult] = useState<AnalysisResult | null>(null);
  const [periodicReview, setPeriodicReview] = useState<PeriodicReviewData | null>(null);
  const [loading, setLoading] = useState(false);
  const [periodicLoading, setPeriodicLoading] = useState(false);
  const [parsing, setParsing] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const [journalPage, setJournalPage] = useState(1);
  const [journalDateFilter, setJournalDateFilter] = useState('');
  const [planPage, setPlanPage] = useState(1);
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);
  const [isPlanOpen, setIsPlanOpen] = useState(false);

  const [generatingPlan, setGeneratingPlan] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const importInputRef = useRef<HTMLInputElement>(null);

  // --- Persistence ---
  useEffect(() => { localStorage.setItem('qm_journal', JSON.stringify(journal)); }, [journal]);
  useEffect(() => { localStorage.setItem('qm_trading_plans', JSON.stringify(tradingPlans)); }, [tradingPlans]);

  // --- Derived Data ---
  const filteredJournal = useMemo(() => {
    let result = [...journal];
    if (journalDateFilter) {
      result = result.filter(entry => new Date(entry.timestamp).toISOString().split('T')[0] === journalDateFilter);
    }
    return result;
  }, [journal, journalDateFilter]);

  const totalJournalPages = Math.ceil(filteredJournal.length / ITEMS_PER_PAGE_JOURNAL);
  const currentJournalItems = filteredJournal.slice((journalPage - 1) * ITEMS_PER_PAGE_JOURNAL, journalPage * ITEMS_PER_PAGE_JOURNAL);

  const totalPlanPages = Math.ceil(tradingPlans.length / ITEMS_PER_PAGE_PLAN);
  const currentPlanItems = tradingPlans.slice((planPage - 1) * ITEMS_PER_PAGE_PLAN, planPage * ITEMS_PER_PAGE_PLAN);

  // --- Handlers ---
  const handlePeriodicReview = async (type: 'week' | 'month') => {
    const days = type === 'week' ? 7 : 30;
    const cutoff = Date.now() - (days * 24 * 60 * 60 * 1000);
    const recentLogs = journal.filter(entry => entry.timestamp >= cutoff);
    if (recentLogs.length < 2) { alert(`历史记录不足`); return; }

    setPeriodicLoading(true);
    try {
      const result = await fetchPeriodicReview(recentLogs, type === 'week' ? '周度' : '月度', currentMarket, settings.geminiKey);
      if (result.periodicData) setPeriodicReview(result.periodicData);
    } catch (err: any) { setError(err.message); }
    finally { setPeriodicLoading(false); }
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setParsing(true);
    try {
      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64String = (reader.result as string).split(',')[1];
        try {
          const parsedData = await parseBrokerageScreenshot(base64String, settings.geminiKey);
          setSnapshot({ ...parsedData, date: new Date().toISOString().split('T')[0] });
        } catch (err: any) { setError("截图解析失败"); }
        finally { setParsing(false); }
      };
      reader.readAsDataURL(file);
    } catch (err) { setParsing(false); }
  };

  const handleAnalyze = async () => {
    if (snapshot.holdings.length === 0) { setError("持仓为空"); return; }
    setLoading(true);
    setAnalysisResult(null);
    try {
      const prompt = `分析持仓：${JSON.stringify(snapshot.holdings)}。要求：Markdown ## 标题分段。给出止盈止损建议。重点分析每个股票的代码和对应的操作理由。`;
      const result = await analyzeWithLLM(currentModel, prompt, true, settings, false, 'day', undefined, currentMarket);
      setAnalysisResult(result);
    } catch (err: any) { setError(err.message); }
    finally { setLoading(false); }
  };

  const handleGeneratePlan = async () => {
    if (!analysisResult) return;
    setGeneratingPlan(true);
    try {
      const { items, summary } = await extractTradingPlan(analysisResult.content, settings.geminiKey);
      const newPlan: DailyTradingPlan = {
        id: crypto.randomUUID(),
        target_date: new Date(Date.now() + 86400000).toISOString().split('T')[0],
        created_at: Date.now(),
        items: items.map(it => ({ ...it, status: 'pending' })),
        strategy_summary: summary
      };
      setTradingPlans(prev => [newPlan, ...prev]);
      setPlanPage(1);
      setIsPlanOpen(true);
    } catch (err: any) { setError("计划生成失败"); }
    finally { setGeneratingPlan(false); }
  };

  const saveToJournal = () => {
    if (!analysisResult) return;
    const newEntry: JournalEntry = {
      id: crypto.randomUUID(),
      timestamp: Date.now(),
      snapshot: { ...snapshot },
      analysis: analysisResult
    };
    setJournal(prev => [newEntry, ...prev]);
    alert("已存档至复盘历史");
  };

  const toggleItemStatus = (planId: string, itemId: string) => {
    setTradingPlans(prev => prev.map(p => {
      if (p.id === planId) {
        return {
          ...p,
          items: p.items.map(it => it.id === itemId ? { ...it, status: it.status === 'completed' ? 'pending' : 'completed' } : it)
        };
      }
      return p;
    }));
  };

  const exportJournalJSON = () => {
    const blob = new Blob([JSON.stringify(journal, null, 2)], { type: "application/json" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a'); a.href = url; a.download = `History_${new Date().toISOString().split('T')[0]}.json`; a.click();
  };

  const importJournalJSON = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (ev) => {
      try {
        const imported = JSON.parse(ev.target?.result as string);
        if (Array.isArray(imported)) { setJournal(imported); alert("导入成功"); }
      } catch (e) { alert("解析失败"); }
    };
    reader.readAsText(file);
  };

  const deletePlan = (id: string) => { setTradingPlans(prev => prev.filter(p => p.id !== id)); };

  const renderAnalysisReport = (content: string) => {
    const sections = content.split(/^##\s+/gm).filter(Boolean);
    return (
      <div className="space-y-4">
        {sections.map((sec, idx) => {
          const lines = sec.trim().split('\n');
          const title = lines[0].trim();
          const body = lines.slice(1).join('\n').trim();
          return (
            <div key={idx} className="bg-white rounded-xl border border-slate-200 p-6">
              <h3 className="text-base font-bold text-slate-800 mb-3 flex items-center gap-2">
                <div className="w-1 h-3.5 bg-blue-600 rounded-full" /> {title}
              </h3>
              <div className="space-y-1.5">
                {body.split('\n').map((line, i) => {
                  if (!line.trim()) return null;
                  let fmt = line.replace(/\*\*(.*?)\*\*/g, '<strong class="text-slate-900">$1</strong>');
                  fmt = fmt.replace(/(买入|加仓|突破)/g, '<span class="text-rose-600 font-bold">$1</span>');
                  fmt = fmt.replace(/(卖出|减仓|跌破)/g, '<span class="text-emerald-600 font-bold">$1</span>');
                  return <p key={i} className="text-sm text-slate-600 leading-relaxed" dangerouslySetInnerHTML={{ __html: fmt }} />;
                })}
              </div>
            </div>
          );
        })}
      </div>
    );
  };

  return (
    <div className="space-y-6 pb-20">
      {/* Dashboard Card */}
      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-8">
          <div>
            <h2 className="text-2xl font-bold text-slate-800 tracking-tight flex items-center gap-2">
              <UploadCloud className="w-6 h-6 text-blue-600" /> 持仓实操管理
            </h2>
            <p className="text-slate-400 text-[10px] uppercase font-bold tracking-widest mt-1">Operational Portfolio Review</p>
          </div>
          <div className="flex gap-2">
            <button onClick={() => setIsPlanOpen(!isPlanOpen)} className="px-4 py-2 text-sm font-bold text-slate-600 bg-slate-50 border border-slate-200 rounded-xl hover:bg-slate-100 transition-all flex items-center gap-2">
              <ListTodo className="w-4 h-4" /> 交易指令库
            </button>
            <button onClick={() => setIsHistoryOpen(!isHistoryOpen)} className="px-4 py-2 text-sm font-bold text-slate-600 bg-slate-50 border border-slate-200 rounded-xl hover:bg-slate-100 transition-all flex items-center gap-2">
              <History className="w-4 h-4" /> 历史复盘库
            </button>
            <button onClick={() => fileInputRef.current?.click()} className="px-5 py-2 bg-blue-600 text-white text-sm font-bold rounded-xl shadow-sm hover:bg-blue-700 transition-all flex items-center gap-2">
              {parsing ? <Loader2 className="w-4 h-4 animate-spin" /> : <Camera className="w-4 h-4" />} {parsing ? '解析中' : '上传截图'}
            </button>
            <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleImageUpload} />
          </div>
        </div>

        {/* History/Import/Export Area */}
        {isHistoryOpen && (
          <div className="mb-8 p-6 bg-slate-50 rounded-2xl border border-slate-200 animate-slide-down">
            <div className="flex justify-between items-center mb-6">
              <h4 className="text-xs font-bold text-slate-400 uppercase tracking-widest">History Management</h4>
              <div className="flex gap-2">
                <button onClick={() => importInputRef.current?.click()} className="text-[10px] font-bold px-3 py-1.5 bg-white border border-slate-200 rounded-lg hover:bg-slate-50">导入数据</button>
                <button onClick={exportJournalJSON} className="text-[10px] font-bold px-3 py-1.5 bg-white border border-slate-200 rounded-lg hover:bg-slate-50">导出备份</button>
                <input type="file" ref={importInputRef} className="hidden" accept=".json" onChange={importJournalJSON} />
              </div>
            </div>
            <div className="space-y-2">
              {filteredJournal.length === 0 ? <p className="text-center py-6 text-slate-300 text-sm">暂无存档记录</p> : 
                filteredJournal.slice(0, 5).map(entry => (
                  <div key={entry.id} onClick={() => {setSnapshot(entry.snapshot); setAnalysisResult(entry.analysis); setIsHistoryOpen(false);}} className="p-3 bg-white rounded-xl border border-slate-100 hover:border-blue-400 cursor-pointer flex justify-between items-center group transition-all">
                    <span className="text-sm font-bold text-slate-700">{new Date(entry.timestamp).toLocaleString()}</span>
                    <ChevronRight className="w-4 h-4 text-slate-200 group-hover:text-blue-500" />
                  </div>
                ))
              }
            </div>
          </div>
        )}

        {/* Assets Table */}
        <div className="overflow-hidden rounded-xl border border-slate-200 mb-6">
          <div className="bg-slate-50 px-6 py-4 flex justify-between items-center border-b">
            <div className="flex gap-8">
              <div>
                <span className="text-[10px] font-bold text-slate-400 block mb-0.5 uppercase tracking-widest">Balance</span>
                <input type="number" value={snapshot.totalAssets} onChange={e => setSnapshot({...snapshot, totalAssets: Number(e.target.value)})} className="bg-transparent text-lg font-bold text-slate-800 w-32 border-b border-dashed border-slate-300 outline-none" />
              </div>
              <div>
                <span className="text-[10px] font-bold text-slate-400 block mb-0.5 uppercase tracking-widest">Ratio %</span>
                <input type="number" value={snapshot.positionRatio || 0} onChange={e => setSnapshot({...snapshot, positionRatio: Number(e.target.value)})} className="bg-transparent text-lg font-bold text-slate-800 w-16 border-b border-dashed border-slate-300 outline-none" />
              </div>
            </div>
            <button onClick={() => setSnapshot({...snapshot, holdings: [...snapshot.holdings, { name: "新股", code: "000000", volume: 0, costPrice: 0, currentPrice: 0, profit: 0, profitRate: "0%", marketValue: 0 }]})} className="text-[10px] font-bold text-blue-600 px-3 py-1.5 hover:bg-blue-50 rounded-lg">新增行</button>
          </div>
          <table className="w-full text-sm">
            <thead className="bg-slate-50/50 text-[10px] font-bold text-slate-400 uppercase border-b">
              <tr><th className="px-6 py-3 text-left">标的</th><th className="px-6 py-3 text-left">代码</th><th className="px-6 py-3 text-left">盈亏%</th><th className="px-6 py-3 text-right">管理</th></tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {snapshot.holdings.map((it, idx) => (
                <tr key={idx} className="hover:bg-slate-50/30 group">
                  <td className="px-6 py-3 font-bold text-slate-700">{it.name}</td>
                  <td className="px-6 py-3 font-mono text-slate-400">{it.code}</td>
                  <td className={`px-6 py-3 font-bold ${it.profit >= 0 ? 'text-rose-500' : 'text-emerald-500'}`}>{it.profitRate}</td>
                  <td className="px-6 py-3 text-right"><button onClick={() => setSnapshot({...snapshot, holdings: snapshot.holdings.filter((_, i) => i !== idx)})} className="p-1.5 text-slate-200 hover:text-rose-500 opacity-0 group-hover:opacity-100"><Trash2 className="w-4 h-4" /></button></td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        <div className="flex justify-end gap-3">
          <div className="flex bg-slate-100 p-1 rounded-xl">
             <button onClick={() => handlePeriodicReview('week')} className="px-4 py-1.5 text-[10px] font-bold text-slate-500 hover:text-blue-600">周复盘</button>
             <button onClick={() => handlePeriodicReview('month')} className="px-4 py-1.5 text-[10px] font-bold text-slate-500 hover:text-blue-600 border-l border-slate-200">月复盘</button>
          </div>
          <button onClick={handleAnalyze} disabled={loading || snapshot.holdings.length === 0} className="px-8 py-2.5 bg-slate-900 text-white rounded-xl text-sm font-bold shadow-sm hover:bg-slate-800 disabled:opacity-50 flex items-center gap-2">
            {loading ? <Loader2 className="w-4 h-4 animate-spin" /> : <TrendingUp className="w-4 h-4" />} 生成报告
          </button>
        </div>
      </div>

      {/* Results View */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 items-start">
        {/* Left: Analysis Report */}
        {analysisResult && (
          <div className="space-y-4">
            <div className="bg-white rounded-2xl p-4 border border-slate-200 flex justify-between items-center">
               <span className="text-xs font-bold text-slate-800 uppercase tracking-widest flex items-center gap-2"><Activity className="w-4 h-4 text-blue-600" /> 复盘分析正文</span>
               <div className="flex gap-2">
                  <button onClick={handleGeneratePlan} disabled={generatingPlan} className="text-[10px] font-bold bg-blue-600 text-white px-3 py-1.5 rounded-lg hover:bg-blue-700 transition-all">生成操作日志</button>
                  <button onClick={saveToJournal} className="text-[10px] font-bold bg-white text-slate-600 border border-slate-200 px-3 py-1.5 rounded-lg hover:bg-slate-50 transition-all">存档</button>
               </div>
            </div>
            {renderAnalysisReport(analysisResult.content)}
          </div>
        )}

        {/* Right: Trading Plan (Action Log Style) */}
        {isPlanOpen && (
          <div className="space-y-4 animate-fade-in">
            <div className="bg-white rounded-2xl p-4 border border-slate-200 flex justify-between items-center">
               <span className="text-xs font-bold text-slate-800 uppercase tracking-widest flex items-center gap-2"><ListTodo className="w-4 h-4 text-emerald-600" /> 盘中执行核对日志</span>
               <div className="text-[10px] font-bold text-slate-400">Total: {tradingPlans.length}</div>
            </div>

            <div className="space-y-4">
              {currentPlanItems.map(plan => (
                <div key={plan.id} className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
                  <div className="bg-slate-50 px-6 py-3 flex justify-between items-center border-b">
                     <span className="text-sm font-bold text-slate-700 tracking-tight">{plan.target_date} 操作核心</span>
                     <div className="flex gap-3">
                        <button onClick={() => {
                          let md = `# 执行日志 (${plan.target_date})\n\n策略摘要: ${plan.strategy_summary}\n\n| 标的 | 代码 | 动作 | 价格 | 理由 | 状态 |\n| :--- | :--- | :--- | :--- | :--- | :--- |\n`;
                          plan.items.forEach(it => md += `| ${it.symbol} | -- | ${it.action} | ${it.price_target} | ${it.reason} | ${it.status} |\n`);
                          const blob = new Blob([md], { type: 'text/markdown' }); const url = URL.createObjectURL(blob);
                          const a = document.createElement('a'); a.href = url; a.download = `Log_${plan.target_date}.md`; a.click();
                        }} className="text-[10px] font-bold text-slate-400 hover:text-blue-600">导出日志</button>
                        <button onClick={() => deletePlan(plan.id)} className="text-[10px] font-bold text-slate-400 hover:text-rose-500">删除</button>
                     </div>
                  </div>
                  <div className="p-5">
                    <p className="text-sm text-slate-500 leading-relaxed mb-6 italic bg-slate-50 p-4 rounded-xl border border-slate-100 border-l-4 border-blue-400">"{plan.strategy_summary}"</p>
                    <div className="space-y-2">
                       {plan.items.map(item => (
                         <div key={item.id} className={`flex items-start gap-3 p-4 rounded-xl border transition-all ${item.status === 'completed' ? 'bg-slate-50 border-slate-100 opacity-50 grayscale' : 'bg-white border-slate-100 hover:border-blue-200 hover:bg-blue-50/10'}`}>
                            <button onClick={() => toggleItemStatus(plan.id, item.id)} className={`mt-0.5 shrink-0 transition-colors ${item.status === 'completed' ? 'text-blue-500' : 'text-slate-200 hover:text-blue-400'}`}>
                               {item.status === 'completed' ? <CheckSquare className="w-5 h-5" /> : <Square className="w-5 h-5" />}
                            </button>
                            <div className="flex-1">
                               <div className="flex justify-between items-center mb-1">
                                  <div className="flex items-center gap-2">
                                     <span className={`text-base font-bold text-slate-800 ${item.status === 'completed' ? 'line-through' : ''}`}>{item.symbol}</span>
                                     <span className={`text-[10px] font-bold px-1.5 py-0.5 rounded uppercase ${item.action === 'buy' ? 'bg-rose-50 text-rose-500' : item.action === 'sell' ? 'bg-emerald-50 text-emerald-500' : 'bg-slate-100 text-slate-500'}`}>
                                        {item.action === 'buy' ? '买入' : item.action === 'sell' ? '卖出' : '持股'}
                                     </span>
                                  </div>
                                  <div className="text-sm font-bold text-slate-800">¥ {item.price_target || '--'}</div>
                               </div>
                               <p className="text-sm text-slate-500 leading-relaxed italic line-clamp-2">{item.reason}</p>
                            </div>
                         </div>
                       ))}
                    </div>
                  </div>
                </div>
              ))}
            </div>

            {totalPlanPages > 1 && (
              <div className="flex justify-center gap-6 mt-6">
                 <button disabled={planPage === 1} onClick={() => setPlanPage(p => p - 1)} className="p-1 text-slate-300 hover:text-blue-600 disabled:opacity-20"><ChevronLeft /></button>
                 <span className="text-[10px] font-bold text-slate-400">{planPage} / {totalPlanPages}</span>
                 <button disabled={planPage === totalPlanPages} onClick={() => setPlanPage(p => p + 1)} className="p-1 text-slate-300 hover:text-blue-600 disabled:opacity-20"><ChevronRight /></button>
              </div>
            )}
          </div>
        )}
      </div>

      {/* Periodic Review Section (Remains intact but minimalist) */}
      {periodicReview && (
        <div className="bg-slate-900 text-white rounded-[2.5rem] p-8 mt-12 shadow-2xl animate-slide-up">
           <div className="flex justify-between items-center mb-8 border-b border-white/10 pb-6">
              <h3 className="text-xl font-bold flex items-center gap-3"><ShieldCheck className="w-6 h-6 text-blue-400" /> 周期战略总结 (Periodic Audit)</h3>
              <div className="text-center"><span className="text-[10px] font-bold text-slate-500 uppercase block">Score</span><span className="text-3xl font-black text-blue-400">{periodicReview.score}</span></div>
           </div>
           <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <div className="space-y-4">
                 <div className="text-[10px] font-bold text-rose-400 uppercase tracking-widest flex items-center gap-2"><CheckCircle2 className="w-4 h-4" /> 行为红榜 (好的方面)</div>
                 <p className="text-sm font-bold text-slate-200">{periodicReview.highlight.title}</p>
                 <div className="space-y-2">
                    {periodicReview.execution.good_behaviors.map((it, i) => (
                       <div key={i} className="text-xs text-slate-400 bg-white/5 p-3 rounded-lg border border-white/5">✓ {it}</div>
                    ))}
                 </div>
              </div>
              <div className="space-y-4">
                 <div className="text-[10px] font-bold text-emerald-400 uppercase tracking-widest flex items-center gap-2"><Zap className="w-4 h-4" /> 纠偏建议 (坏的方面)</div>
                 <p className="text-sm font-bold text-slate-200">{periodicReview.lowlight.title}</p>
                 <div className="space-y-3">
                    {periodicReview.execution.bad_behaviors.map((it, i) => (
                       <div key={i} className="p-4 bg-slate-800 rounded-xl border-l-4 border-emerald-500">
                          <p className="text-xs font-bold text-slate-200">{it}</p>
                          <p className="text-[10px] text-emerald-400 mt-2">指令：严格遵守止损线，拒绝盘中情绪化加仓。</p>
                       </div>
                    ))}
                 </div>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { ModelProvider, AnalysisResult, UserSettings, MarketType, HoldingsSnapshot, HoldingItemDetailed, JournalEntry, DailyTradingPlan, PlanItem, PeriodicReviewData } from '../types';
import { analyzeWithLLM } from '../services/llmAdapter';
import { parseBrokerageScreenshot, extractTradingPlan, fetchPeriodicReview } from '../services/geminiService';
import { Upload, Loader2, Save, Download, UploadCloud, History, Trash2, Camera, Check, X, TrendingUp, Activity, Target, Calendar, ChevronLeft, ChevronRight, Filter, ListTodo, Clock, FileText, FileDown, CheckCircle2, Square, CheckSquare, AlertCircle, ShieldCheck, Zap, Database } from 'lucide-react';

const ITEMS_PER_PAGE_JOURNAL = 5;
const ITEMS_PER_PAGE_PLAN = 3;

export const HoldingsReview: React.FC<{
  currentModel: ModelProvider;
  currentMarket: MarketType;
  settings: UserSettings;
  onOpenSettings?: () => void;
}> = ({ currentModel, currentMarket, settings, onOpenSettings }) => {
  // --- States ---
  const [snapshot, setSnapshot] = useState<HoldingsSnapshot>({
    totalAssets: 0,
    positionRatio: 0,
    date: new Date().toISOString().split('T')[0],
    holdings: []
  });

  const [journal, setJournal] = useState<JournalEntry[]>(() => {
    const saved = localStorage.getItem('qm_journal');
    return saved ? JSON.parse(saved) : [];
  });

  const [tradingPlans, setTradingPlans] = useState<DailyTradingPlan[]>(() => {
    const saved = localStorage.getItem('qm_trading_plans');
    return saved ? JSON.parse(saved) : [];
  });

  const [analysisResult, setAnalysisResult] = useState<AnalysisResult | null>(null);
  const [periodicReview, setPeriodicReview] = useState<PeriodicReviewData | null>(null);
  const [loading, setLoading] = useState(false);
  const [periodicLoading, setPeriodicLoading] = useState(false);
  const [parsing, setParsing] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const [journalDateFilter, setJournalDateFilter] = useState('');
  const [planPage, setPlanPage] = useState(1);
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);
  const [isPlanOpen, setIsPlanOpen] = useState(true); // 默认开启指令库

  const [generatingPlan, setGeneratingPlan] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const importInputRef = useRef<HTMLInputElement>(null);

  // --- Persistence ---
  useEffect(() => { localStorage.setItem('qm_journal', JSON.stringify(journal)); }, [journal]);
  useEffect(() => { localStorage.setItem('qm_trading_plans', JSON.stringify(tradingPlans)); }, [tradingPlans]);

  // --- Derived Data ---
  const filteredJournal = useMemo(() => {
    let result = [...journal];
    if (journalDateFilter) {
      result = result.filter(entry => new Date(entry.timestamp).toISOString().split('T')[0] === journalDateFilter);
    }
    return result;
  }, [journal, journalDateFilter]);

  const totalPlanPages = Math.ceil(tradingPlans.length / ITEMS_PER_PAGE_PLAN);
  const currentPlanItems = tradingPlans.slice((planPage - 1) * ITEMS_PER_PAGE_PLAN, planPage * ITEMS_PER_PAGE_PLAN);

  // --- Handlers ---
  const handlePeriodicReview = async (type: 'week' | 'month') => {
    const days = type === 'week' ? 7 : 30;
    const cutoff = Date.now() - (days * 24 * 60 * 60 * 1000);
    const recentLogs = journal.filter(entry => entry.timestamp >= cutoff);
    if (recentLogs.length < 2) { alert(`复盘数据不足，至少需要2条记录`); return; }

    setPeriodicLoading(true);
    try {
      const result = await fetchPeriodicReview(recentLogs, type === 'week' ? '周度' : '月度', currentMarket, settings.geminiKey);
      if (result.periodicData) setPeriodicReview(result.periodicData);
    } catch (err: any) { setError(err.message); }
    finally { setPeriodicLoading(false); }
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setParsing(true);
    try {
      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64String = (reader.result as string).split(',')[1];
        try {
          const parsedData = await parseBrokerageScreenshot(base64String, settings.geminiKey);
          setSnapshot({ ...parsedData, date: new Date().toISOString().split('T')[0] });
        } catch (err: any) { setError("截图解析失败"); }
        finally { setParsing(false); }
      };
      reader.readAsDataURL(file);
    } catch (err) { setParsing(false); }
  };

  const handleAnalyze = async () => {
    if (snapshot.holdings.length === 0) { setError("持仓列表为空"); return; }
    setLoading(true);
    setAnalysisResult(null);
    try {
      const prompt = `请深度复盘我的 A 股持仓：${JSON.stringify(snapshot.holdings)}。
      要求：使用 Markdown ## 标题分段。给出具体的止盈止损建议。重点分析每个股票的代码、名称和对应的操作理由。`;
      const result = await analyzeWithLLM(currentModel, prompt, true, settings, false, 'day', undefined, currentMarket);
      setAnalysisResult(result);
    } catch (err: any) { setError(err.message); }
    finally { setLoading(false); }
  };

  const handleGeneratePlan = async () => {
    if (!analysisResult) return;
    setGeneratingPlan(true);
    try {
      const { items, summary } = await extractTradingPlan(analysisResult.content, settings.geminiKey);
      const newPlan: DailyTradingPlan = {
        id: crypto.randomUUID(),
        target_date: new Date(Date.now() + 86400000).toISOString().split('T')[0],
        created_at: Date.now(),
        items: items.map(it => ({ ...it, status: 'pending' })),
        strategy_summary: summary
      };
      setTradingPlans(prev => [newPlan, ...prev]);
      setPlanPage(1);
      setIsPlanOpen(true);
    } catch (err: any) { setError("计划生成失败"); }
    finally { setGeneratingPlan(false); }
  };

  const saveToJournal = () => {
    if (!analysisResult) return;
    const newEntry: JournalEntry = {
      id: crypto.randomUUID(),
      timestamp: Date.now(),
      snapshot: { ...snapshot },
      analysis: analysisResult
    };
    setJournal(prev => [newEntry, ...prev]);
    alert("已成功存入历史库");
  };

  const toggleItemStatus = (planId: string, itemId: string) => {
    setTradingPlans(prev => prev.map(p => {
      if (p.id === planId) {
        return {
          ...p,
          items: p.items.map(it => it.id === itemId ? { ...it, status: it.status === 'completed' ? 'pending' : 'completed' } : it)
        };
      }
      return p;
    }));
  };

  const exportJournalJSON = () => {
    const blob = new Blob([JSON.stringify({ journal, tradingPlans }, null, 2)], { type: "application/json" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a'); a.href = url; a.download = `QuantMind_Backup_${new Date().toISOString().split('T')[0]}.json`; a.click();
  };

  const importJournalJSON = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (ev) => {
      try {
        const imported = JSON.parse(ev.target?.result as string);
        if (imported.journal) setJournal(imported.journal);
        if (imported.tradingPlans) setTradingPlans(imported.tradingPlans);
        alert("历史存档导入成功！");
      } catch (e) { alert("导入格式错误"); }
    };
    reader.readAsText(file);
  };

  const deletePlan = (id: string) => { setTradingPlans(prev => prev.filter(p => p.id !== id)); };

  const renderAnalysisReport = (content: string) => {
    const sections = content.split(/^##\s+/gm).filter(Boolean);
    return (
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {sections.map((sec, idx) => {
          const lines = sec.trim().split('\n');
          const title = lines[0].trim();
          const body = lines.slice(1).join('\n').trim();
          return (
            <div key={idx} className="bg-white rounded-xl border border-slate-200 p-5">
              <h3 className="text-sm font-bold text-slate-800 mb-3 flex items-center gap-2">
                <div className="w-1 h-3.5 bg-blue-600 rounded-full" /> {title}
              </h3>
              <div className="space-y-1.5">
                {body.split('\n').map((line, i) => {
                  if (!line.trim()) return null;
                  let fmt = line.replace(/\*\*(.*?)\*\*/g, '<strong class="text-slate-900">$1</strong>');
                  fmt = fmt.replace(/(买入|加仓|突破)/g, '<span class="text-rose-600 font-bold">$1</span>');
                  fmt = fmt.replace(/(卖出|减仓|跌破)/g, '<span class="text-emerald-600 font-bold">$1</span>');
                  return <p key={i} className="text-sm text-slate-600 leading-relaxed" dangerouslySetInnerHTML={{ __html: fmt }} />;
                })}
              </div>
            </div>
          );
        })}
      </div>
    );
  };

  return (
    <div className="space-y-6 pb-24 max-w-6xl mx-auto">
      {/* Top Controller */}
      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-8">
          <div>
            <h2 className="text-2xl font-bold text-slate-800 flex items-center gap-2 tracking-tight">
              <Database className="w-6 h-6 text-blue-600" /> 持仓实操档案
            </h2>
            <p className="text-slate-400 text-[10px] uppercase font-bold tracking-widest mt-1">Operational Archive & Review</p>
          </div>
          <div className="flex gap-2">
            <button onClick={() => setIsHistoryOpen(!isHistoryOpen)} className="px-4 py-2 text-sm font-bold text-slate-600 bg-slate-50 border border-slate-200 rounded-xl hover:bg-slate-100 flex items-center gap-2">
              <History className="w-4 h-4" /> 历史复盘库
            </button>
            <button onClick={() => fileInputRef.current?.click()} className="px-5 py-2 bg-blue-600 text-white text-sm font-bold rounded-xl shadow-sm hover:bg-blue-700 transition-all flex items-center gap-2">
              {parsing ? <Loader2 className="w-4 h-4 animate-spin" /> : <Camera className="w-4 h-4" />} 上传截图
            </button>
            <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleImageUpload} />
          </div>
        </div>

        {/* Backup & Safety Area */}
        {isHistoryOpen && (
          <div className="mb-8 p-6 bg-slate-50 rounded-2xl border border-slate-200 animate-slide-down">
            <div className="flex justify-between items-center mb-6">
              <h4 className="text-xs font-bold text-slate-400 uppercase tracking-widest flex items-center gap-2">
                <ShieldCheck className="w-4 h-4 text-emerald-500" /> 历史数据资产保护
              </h4>
              <div className="flex gap-2">
                <button onClick={() => importInputRef.current?.click()} className="text-[10px] font-bold px-3 py-1.5 bg-white border border-slate-200 rounded-lg hover:bg-slate-50">导入旧存档</button>
                <button onClick={exportJournalJSON} className="text-[10px] font-bold px-3 py-1.5 bg-blue-50 text-blue-600 border border-blue-100 rounded-lg hover:bg-blue-100">导出备份(JSON)</button>
                <input type="file" ref={importInputRef} className="hidden" accept=".json" onChange={importJournalJSON} />
              </div>
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-2">
              {filteredJournal.length === 0 ? <p className="col-span-2 text-center py-6 text-slate-300 text-sm italic">暂无复盘历史记录</p> : 
                filteredJournal.slice(0, 10).map(entry => (
                  <div key={entry.id} onClick={() => {setSnapshot(entry.snapshot); setAnalysisResult(entry.analysis); setIsHistoryOpen(false);}} className="p-3 bg-white rounded-xl border border-slate-100 hover:border-blue-400 cursor-pointer flex justify-between items-center group transition-all">
                    <span className="text-sm font-bold text-slate-700">{new Date(entry.timestamp).toLocaleString()}</span>
                    <div className="flex items-center gap-2">
                       <span className="text-[10px] text-slate-400 font-mono">[{entry.snapshot.holdings.length}标的]</span>
                       <ChevronRight className="w-4 h-4 text-slate-200 group-hover:text-blue-500" />
                    </div>
                  </div>
                ))
              }
            </div>
          </div>
        )}

        {/* Current Table */}
        <div className="overflow-hidden rounded-xl border border-slate-200 mb-6">
          <div className="bg-slate-50 px-6 py-4 flex justify-between items-center border-b">
            <div className="flex gap-8">
              <div>
                <span className="text-[10px] font-bold text-slate-400 block mb-0.5 uppercase tracking-widest">Total Value</span>
                <input type="number" value={snapshot.totalAssets} onChange={e => setSnapshot({...snapshot, totalAssets: Number(e.target.value)})} className="bg-transparent text-lg font-bold text-slate-800 w-32 border-b border-dashed border-slate-300 outline-none focus:border-blue-500" />
              </div>
              <div>
                <span className="text-[10px] font-bold text-slate-400 block mb-0.5 uppercase tracking-widest">Ratio %</span>
                <input type="number" value={snapshot.positionRatio || 0} onChange={e => setSnapshot({...snapshot, positionRatio: Number(e.target.value)})} className="bg-transparent text-lg font-bold text-slate-800 w-16 border-b border-dashed border-slate-300 outline-none focus:border-blue-500" />
              </div>
            </div>
            <button onClick={() => setSnapshot({...snapshot, holdings: [...snapshot.holdings, { name: "新持仓", code: "000000", volume: 0, costPrice: 0, currentPrice: 0, profit: 0, profitRate: "0%", marketValue: 0 }]})} className="text-[10px] font-bold text-blue-600 px-3 py-1.5 hover:bg-blue-50 rounded-lg">添加持仓</button>
          </div>
          <table className="w-full text-sm">
            <thead className="bg-slate-50/50 text-[10px] font-bold text-slate-400 uppercase border-b">
              <tr><th className="px-6 py-3 text-left">名称/代码</th><th className="px-6 py-3 text-left">持仓详情</th><th className="px-6 py-3 text-left">盈亏</th><th className="px-6 py-3 text-right">操作</th></tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {snapshot.holdings.map((it, idx) => (
                <tr key={idx} className="hover:bg-slate-50/30 group">
                  <td className="px-6 py-3 font-bold text-slate-700">
                    <div className="text-sm">{it.name}</div>
                    <div className="text-[10px] font-mono text-slate-400">{it.code}</div>
                  </td>
                  <td className="px-6 py-3">
                    <div className="text-slate-600 font-bold">{it.volume} 股</div>
                    <div className="text-xs text-slate-400">成本: {it.costPrice}</div>
                  </td>
                  <td className={`px-6 py-3 font-bold ${it.profit >= 0 ? 'text-rose-500' : 'text-emerald-500'}`}>
                    <div>{it.profitRate}</div>
                    <div className="text-[10px]">¥ {it.profit.toLocaleString()}</div>
                  </td>
                  <td className="px-6 py-3 text-right">
                    <button onClick={() => setSnapshot({...snapshot, holdings: snapshot.holdings.filter((_, i) => i !== idx)})} className="p-1.5 text-slate-200 hover:text-rose-500 opacity-0 group-hover:opacity-100 transition-all"><Trash2 className="w-4 h-4" /></button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        <div className="flex justify-end gap-3">
          <div className="flex bg-slate-100 p-1 rounded-xl border border-slate-200">
             <button onClick={() => handlePeriodicReview('week')} className="px-4 py-1.5 text-[10px] font-bold text-slate-500 hover:text-blue-600">周度战略总结</button>
             <button onClick={() => handlePeriodicReview('month')} className="px-4 py-1.5 text-[10px] font-bold text-slate-500 hover:text-blue-600 border-l border-slate-200">月度战略总结</button>
          </div>
          <button onClick={handleAnalyze} disabled={loading || snapshot.holdings.length === 0} className="px-8 py-2.5 bg-slate-900 text-white rounded-xl text-sm font-bold shadow-sm hover:bg-slate-800 disabled:opacity-50 flex items-center gap-2">
            {loading ? <Loader2 className="w-4 h-4 animate-spin" /> : <TrendingUp className="w-4 h-4" />} 生成诊断报告
          </button>
        </div>
      </div>

      {/* Main Results Stack (Vertical) */}
      <div className="space-y-8 animate-fade-in">

        {/* Section 1: Analysis Results */}
        {analysisResult && (
          <div className="space-y-4">
            <div className="flex justify-between items-center px-2">
               <h3 className="text-sm font-bold text-slate-800 flex items-center gap-2 uppercase tracking-widest"><Activity className="w-4 h-4 text-blue-600" /> 复盘分析报告</h3>
               <div className="flex gap-2">
                  <button onClick={handleGeneratePlan} disabled={generatingPlan} className="text-[10px] font-bold bg-blue-600 text-white px-3 py-1.5 rounded-lg hover:bg-blue-700">转化为执行指令</button>
