        )}

        {/* Section 2: Trading Instructions (Full Width) */}
        {isPlanOpen && tradingPlans.length > 0 && (
          <div className="space-y-4">
            <div className="flex justify-between items-center px-2">
               <h3 className="text-sm font-bold text-slate-800 flex items-center gap-2 uppercase tracking-widest"><ListTodo className="w-4 h-4 text-emerald-600" /> 次日交易执行日志</h3>
               <span className="text-[10px] font-bold text-slate-400">指令记录: {tradingPlans.length} 份</span>
            </div>

            <div className="space-y-6">
              {currentPlanItems.map(plan => (
                <div key={plan.id} className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden animate-slide-up">
                  <div className="bg-slate-50 px-6 py-3.5 flex justify-between items-center border-b border-slate-200">
                     <div className="flex items-center gap-3">
                        <span className="text-sm font-bold text-slate-800">{plan.target_date} 执行策略</span>
                        <span className="text-[10px] text-slate-400 font-mono">Created: {new Date(plan.created_at).toLocaleTimeString()}</span>
                     </div>
                     <div className="flex gap-4">
                        <button onClick={() => {
                          let md = `# 交易执行日志 (${plan.target_date})\n\n策略核心: ${plan.strategy_summary}\n\n| 标的 | 代码 | 动作 | 价格建议 | 理由 | 状态 |\n| :--- | :--- | :--- | :--- | :--- | :--- |\n`;
                          plan.items.forEach(it => md += `| ${it.symbol} | -- | ${it.action} | ${it.price_target} | ${it.reason} | ${it.status === 'completed' ? '已执行' : '待处理'} |\n`);
                          const blob = new Blob([md], { type: 'text/markdown' }); const url = URL.createObjectURL(blob);
                          const a = document.createElement('a'); a.href = url; a.download = `Plan_Log_${plan.target_date}.md`; a.click();
                        }} className="text-[10px] font-bold text-slate-400 hover:text-blue-600 flex items-center gap-1 uppercase">
                           <FileDown className="w-3.5 h-3.5" /> 导出 MD 日志
                        </button>
                        <button onClick={() => deletePlan(plan.id)} className="text-[10px] font-bold text-slate-400 hover:text-rose-500 uppercase">删除记录</button>
                     </div>
                  </div>
                  <div className="p-6">
                    <p className="text-sm text-slate-500 leading-relaxed mb-6 italic bg-slate-50/50 p-4 rounded-xl border border-slate-100 border-l-4 border-emerald-400">
                      "{plan.strategy_summary}"
                    </p>
                    <div className="grid grid-cols-1 gap-2">
                       {plan.items.map(item => (
                         <div key={item.id} className={`flex items-start gap-4 p-4 rounded-xl border transition-all ${item.status === 'completed' ? 'bg-slate-50 border-slate-100 opacity-50' : 'bg-white border-slate-100 hover:border-blue-200 hover:bg-blue-50/20'}`}>
                            <button onClick={() => toggleItemStatus(plan.id, item.id)} className={`mt-0.5 shrink-0 transition-colors ${item.status === 'completed' ? 'text-blue-500' : 'text-slate-200 hover:text-blue-400'}`}>
                               {item.status === 'completed' ? <CheckSquare className="w-5.5 h-5.5" /> : <Square className="w-5.5 h-5.5" />}
                            </button>
                            <div className="flex-1">
                               <div className="flex flex-col sm:flex-row sm:justify-between sm:items-center mb-1 gap-2">
                                  <div className="flex items-center gap-3">
                                     <div className="flex flex-col">
                                        <span className={`text-base font-bold text-slate-800 ${item.status === 'completed' ? 'line-through' : ''}`}>{item.symbol}</span>
                                        <span className="text-[10px] font-mono text-slate-400">CODE: {item.id.split('-')[0].toUpperCase()}</span>
                                     </div>
                                     <span className={`text-[10px] font-bold px-1.5 py-0.5 rounded uppercase tracking-tighter ${item.action === 'buy' ? 'bg-rose-50 text-rose-500' : item.action === 'sell' ? 'bg-emerald-50 text-emerald-500' : 'bg-slate-100 text-slate-500'}`}>
                                        {item.action === 'buy' ? '买入指令' : item.action === 'sell' ? '卖出指令' : '持仓观察'}
                                     </span>
                                  </div>
                                  <div className="text-sm font-bold text-slate-800 bg-slate-100 px-3 py-1 rounded-lg">建议价: ¥ {item.price_target || '--'}</div>
                               </div>
                               <p className="text-sm text-slate-500 leading-relaxed mt-2">{item.reason}</p>
                            </div>
                         </div>
                       ))}
                    </div>
                  </div>
                </div>
              ))}
            </div>

            {totalPlanPages > 1 && (
              <div className="flex justify-center gap-6 mt-6">
                 <button disabled={planPage === 1} onClick={() => setPlanPage(p => p - 1)} className="p-1 text-slate-300 hover:text-blue-600 disabled:opacity-20"><ChevronLeft /></button>
                 <span className="text-[10px] font-bold text-slate-400">{planPage} / {totalPlanPages}</span>
                 <button disabled={planPage === totalPlanPages} onClick={() => setPlanPage(p => p + 1)} className="p-1 text-slate-300 hover:text-blue-600 disabled:opacity-20"><ChevronRight /></button>
              </div>
            )}
          </div>
        )}
      </div>

      {/* Periodic Review (Always at bottom) */}
      {periodicReview && (
        <div className="bg-slate-900 text-white rounded-[2.5rem] p-10 mt-12 shadow-2xl animate-slide-up">
           <div className="flex justify-between items-center mb-10 border-b border-white/10 pb-6">
              <h3 className="text-xl font-bold flex items-center gap-3"><ShieldCheck className="w-6 h-6 text-blue-400" /> 交易周期性宏观评估 (Periodic Review)</h3>
              <div className="text-center"><span className="text-[10px] font-bold text-slate-500 uppercase block">Execution Score</span><span className="text-3xl font-black text-blue-400">{periodicReview.score}</span></div>
           </div>
           <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
              <div className="space-y-6">
                 <div className="text-[10px] font-bold text-rose-400 uppercase tracking-widest flex items-center gap-2"><CheckCircle2 className="w-4 h-4" /> 行为红榜 (Positive)</div>
                 <p className="text-base font-bold text-slate-200">{periodicReview.highlight.title}</p>
                 <div className="space-y-2">
                    {periodicReview.execution.good_behaviors.map((it, i) => (
                       <div key={i} className="text-sm text-slate-300 bg-white/5 p-4 rounded-xl border border-white/5">✓ {it}</div>
                    ))}
                 </div>
              </div>
              <div className="space-y-6">
                 <div className="text-[10px] font-bold text-emerald-400 uppercase tracking-widest flex items-center gap-2"><Zap className="w-4 h-4" /> 执行偏差纠偏 (Adjustments)</div>
                 <p className="text-base font-bold text-slate-200">{periodicReview.lowlight.title}</p>
                 <div className="space-y-3">
                    {periodicReview.execution.bad_behaviors.map((it, i) => (
                       <div key={i} className="p-5 bg-slate-800 rounded-xl border-l-4 border-emerald-500">
                          <p className="text-sm font-bold text-slate-200">{it}</p>
                          <p className="text-xs text-emerald-400 mt-3 font-medium tracking-tight italic">修正建议：必须严格遵守预设止损点，切忌由于情绪波动临时修改计划。</p>
                       </div>
                    ))}
                 </div>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

