              </h3>
              <div className="space-y-2">
                {body.split('\n').map((line, i) => {
                  if (!line.trim()) return null;
                  let fmt = line.replace(/\*\*(.*?)\*\*/g, '<strong class="text-slate-900">$1</strong>');
                  fmt = fmt.replace(/(买入|加仓|突破|建议买入)/g, '<span class="text-rose-600 font-bold">$1</span>');
                  fmt = fmt.replace(/(卖出|减仓|跌破|建议卖出|止损)/g, '<span class="text-emerald-600 font-bold">$1</span>');
                  return <p key={i} className="text-sm text-slate-600 leading-relaxed" dangerouslySetInnerHTML={{ __html: fmt }} />;
