import { GoogleGenAI, Schema, Type } from "@google/genai";
import { AnalysisResult, ModelProvider, MarketType, SectorTiering } from "../types";

const sectorTierSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    sector_name: { type: Type.STRING },
    lifecycle_stage: { type: Type.STRING, enum: ['孵化期', '成长阶段', '高潮爆发', '衰退期', '末端补涨'] },
    health_score: { type: Type.NUMBER },
    structure_verdict: { type: Type.STRING },
    tiers: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          level: { type: Type.NUMBER },
          label: { type: Type.STRING },
          stocks: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                code: { type: Type.STRING },
                status: { type: Type.STRING },
                logic: { type: Type.STRING }
              },
              required: ["name", "code", "status", "logic"]
            }
          }
        },
        required: ["level", "label", "stocks"]
      }
    },
    rotation_analysis: { type: Type.STRING },
    risk_warning: { type: Type.STRING }
  },
  required: ["sector_name", "lifecycle_stage", "health_score", "structure_verdict", "tiers", "rotation_analysis", "risk_warning"]
};

export const fetchSectorLifecycle = async (
  sector: string,
  market: MarketType,
  apiKey: string
): Promise<AnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey });

  const prompt = `
    作为资深游资策略分析师，请利用 googleSearch 深度调研当前 ${market} 市场的热门板块: "${sector}" 的梯队结构。

    【核心分析逻辑】
    1. 识别一梯队(龙头): 谁是空间龙？谁是领涨？
    2. 识别二梯队(中军): 哪些权重大票或核心细分在跟进？
    3. 识别三梯队(补涨): 哪些低位个股在今天或昨天开始突然爆发？

    【生命周期研判】
    - 如果只有龙头涨，板块在“孵化期”。
    - 如果龙头、中军齐涨，在“成长爆发期”。
    - 如果龙头滞涨，三梯队乱拉，且出现大面积补涨，则处于“高潮末端”或“风险期”。

    必须输出 JSON。
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json",
      responseSchema: sectorTierSchema
    }
  });

  const text = response.text || "{}";
  const parsed = JSON.parse(text);

  return {
    content: text,
    timestamp: Date.now(),
    modelUsed: ModelProvider.GEMINI_INTL,
    isStructured: true,
    sectorTierData: parsed,
    market
  };
};

import React, { useState, useEffect } from 'react';
import { ModelProvider, MarketType, AnalysisResult } from '../types';
import { fetchSectorLifecycle } from '../services/sectorService';
import { Layers3, Search, Loader2, Zap, AlertTriangle, ShieldCheck, TrendingUp, Info, ChevronRight, ArrowRight, Sparkles, Activity, Timer } from 'lucide-react';

export const SectorLifecycle: React.FC<{
  currentModel: ModelProvider;
  currentMarket: MarketType;
  settings: any;
  onOpenSettings: () => void;
}> = ({ currentModel, currentMarket, settings, onOpenSettings }) => {
  const [sector, setSector] = useState('');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<AnalysisResult | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [elapsed, setElapsed] = useState(0);

  useEffect(() => {
    let interval: any;
    if (loading) {
      setElapsed(0);
      interval = setInterval(() => setElapsed(prev => prev + 1), 1000);
    }
    return () => clearInterval(interval);
  }, [loading]);

  const handleAnalyze = async () => {
    if (!sector) return;
    if (!settings.geminiKey) {
      onOpenSettings();
      return;
    }
    setLoading(true);
    setError(null);
    setResult(null);
    try {
      const data = await fetchSectorLifecycle(sector, currentMarket, settings.geminiKey);
      setResult(data);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const data = result?.sectorTierData;

  const getStageColor = (stage: string) => {
    if (stage.includes('孵化')) return 'text-blue-500 bg-blue-50 border-blue-200';
    if (stage.includes('成长')) return 'text-emerald-500 bg-emerald-50 border-emerald-200';
    if (stage.includes('爆发')) return 'text-rose-500 bg-rose-50 border-rose-200 animate-pulse';
    if (stage.includes('补涨')) return 'text-amber-500 bg-amber-50 border-amber-200';
    return 'text-slate-500 bg-slate-50 border-slate-200';
  };

  return (
    <div className="space-y-6 animate-fade-in max-w-7xl mx-auto pb-20">
      {/* Search Header */}
      <div className="bg-white rounded-3xl shadow-sm border border-slate-200 p-8 md:p-10 relative overflow-hidden">
        <div className="relative z-10">
          <h2 className="text-3xl font-black text-slate-900 flex items-center gap-4 mb-4">
             <div className="p-3 bg-indigo-600 rounded-2xl text-white shadow-xl shadow-indigo-100">
               <Layers3 className="w-8 h-8" />
             </div>
             周期梯队研判
          </h2>
          <p className="text-slate-500 text-lg max-w-2xl font-medium mb-8">
            识别板块内部的“梯队分化”，通过龙头与补涨龙的联动关系，判断行情是否已进入风险末端。
          </p>

          <div className="flex flex-col md:flex-row gap-3">
             <div className="flex-1 relative">
                <input 
                  type="text" 
                  value={sector}
                  onChange={e => setSector(e.target.value)}
                  placeholder="输入关注板块，如“卫星互联网”或“人形机器人”..."
                  className="w-full h-16 pl-14 pr-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold text-lg transition-all"
                />
                <Search className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-400 w-6 h-6" />
             </div>
             <button 
                onClick={handleAnalyze}
                disabled={loading || !sector}
                className="px-10 h-16 bg-slate-900 text-white rounded-2xl font-black shadow-xl flex items-center justify-center gap-3 transition-all active:scale-95 disabled:opacity-50"
             >
                {loading ? <Loader2 className="w-6 h-6 animate-spin" /> : <Zap className="w-6 h-6" />}
                {loading ? `全网扫描中(${elapsed}s)` : '分析板块生命周期'}
             </button>
          </div>
        </div>
      </div>

      {error && (
        <div className="p-6 bg-rose-50 border border-rose-100 rounded-2xl flex items-center gap-4 text-rose-700 font-bold">
           <AlertTriangle className="w-6 h-6" /> {error}
        </div>
      )}

      {loading && (
        <div className="py-20 flex flex-col items-center justify-center bg-white rounded-3xl border border-dashed border-slate-200 animate-pulse">
           <Activity className="w-16 h-16 text-indigo-400 mb-6" />
           <p className="font-black text-slate-400 text-xl tracking-tight">AI 正在调取实时交易数据与游资研报...</p>
        </div>
      )}

      {data && (
        <div className="space-y-8 animate-slide-up">
           {/* Summary Dashboard */}
           <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
              <div className="lg:col-span-1 bg-white p-8 rounded-3xl border border-slate-200 shadow-sm flex flex-col items-center justify-center text-center">
                 <div className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">结构健康度</div>
                 <div className="relative w-32 h-32 flex items-center justify-center">
                    <svg className="w-full h-full transform -rotate-90">
                       <circle cx="64" cy="64" r="58" fill="none" stroke="#f1f5f9" strokeWidth="10" />
                       <circle cx="64" cy="64" r="58" fill="none" stroke="#4f46e5" strokeWidth="10" strokeDasharray="364.4" strokeDashoffset={364.4 * (1 - data.health_score/100)} className="transition-all duration-1000" />
                    </svg>
                    <span className="absolute text-3xl font-black text-slate-800">{data.health_score}</span>
                 </div>
              </div>

              <div className="lg:col-span-3 bg-slate-900 rounded-3xl p-8 text-white relative overflow-hidden">
                 <div className="relative z-10 h-full flex flex-col justify-center">
                    <div className="flex items-center gap-3 mb-4">
                       <span className={`px-4 py-1.5 rounded-full text-xs font-black uppercase tracking-widest border ${getStageColor(data.lifecycle_stage)}`}>
                          {data.lifecycle_stage}
                       </span>
                       <h3 className="text-2xl font-black">{data.sector_name} · 结构洞察</h3>
                    </div>
                    <p className="text-slate-300 text-lg font-medium italic leading-relaxed">
                       "{data.structure_verdict}"
                    </p>
                    <div className="mt-6 flex items-center gap-2 text-rose-400 text-sm font-bold bg-rose-400/10 p-4 rounded-xl border border-rose-400/20">
                       <AlertTriangle className="w-5 h-5" /> 风险预警: {data.risk_warning}
                    </div>
                 </div>
                 <Timer className="absolute right-[-20px] bottom-[-20px] w-64 h-64 text-white/5" />
              </div>
           </div>

           {/* Tiered Columns */}
           <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
              {data.tiers.sort((a,b)=>a.level-b.level).map((tier, idx) => (
                 <div key={idx} className={`bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden flex flex-col h-full hover:shadow-xl transition-all ${tier.level === 1 ? 'border-t-8 border-t-rose-500' : tier.level === 2 ? 'border-t-8 border-t-indigo-500' : 'border-t-8 border-t-amber-500'}`}>
                    <div className="bg-slate-50 px-6 py-4 border-b border-slate-200 flex justify-between items-center">
                       <h4 className="font-black text-slate-800 text-lg flex items-center gap-2">
                          <span className={`w-6 h-6 rounded flex items-center justify-center text-[10px] text-white ${tier.level === 1 ? 'bg-rose-500' : tier.level === 2 ? 'bg-indigo-500' : 'bg-amber-500'}`}>
                             T{tier.level}
                          </span>
                          {tier.label}
                       </h4>
                       <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">梯队成员</span>
                    </div>
                    <div className="p-6 space-y-4 flex-1">
                       {tier.stocks.map((stock, sIdx) => (
                          <div key={sIdx} className="p-4 bg-slate-50 rounded-2xl border border-slate-100 group hover:border-indigo-400 hover:bg-white transition-all">
                             <div className="flex justify-between items-center mb-2">
                                <div className="font-black text-slate-800 text-base">
                                   {stock.name} <span className="text-xs font-mono text-slate-400 font-normal ml-1">{stock.code}</span>
                                </div>
                                <span className={`text-[10px] font-black px-2 py-0.5 rounded border ${
                                   stock.status.includes('封板') || stock.status.includes('新高') ? 'bg-rose-50 text-rose-600 border-rose-100' : 'bg-slate-200 text-slate-500 border-slate-300'
                                }`}>
                                   {stock.status}
                                </span>
                             </div>
                             <p className="text-xs text-slate-500 font-bold leading-relaxed">{stock.logic}</p>
                          </div>
                       ))}
                    </div>
                 </div>
              ))}
           </div>

           {/* Rotation Logic */}
           <div className="bg-white p-10 rounded-[2.5rem] border border-slate-200 shadow-sm">
              <h3 className="text-xl font-black text-slate-900 mb-6 flex items-center gap-3">
                 <Sparkles className="w-6 h-6 text-amber-500" />
                 资金轮动及博弈细节 (Rotation Logic)
              </h3>
              <p className="text-slate-600 leading-relaxed font-bold text-lg bg-slate-50 p-8 rounded-3xl italic">
                 {data.rotation_analysis}
              </p>
           </div>

           <div className="text-center py-10">
              <div className="inline-flex items-center gap-3 px-6 py-3 bg-slate-100 rounded-full text-[11px] text-slate-400 font-black uppercase tracking-[0.3em]">
                 <Info className="w-4 h-4" /> 梯队逻辑基于短线情绪研判，不构成长线投资建议
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

