export enum ModelProvider {
  GEMINI_INTL = 'gemini-intl',
  HUNYUAN_CN = 'hunyuan-cn'
}

export enum MarketType {
  CN = 'CN',
  HK = 'HK',
  US = 'US'
}

export interface UserSettings {
  hunyuanKey?: string;
  geminiKey?: string;
}

export interface GroundingSource {
  uri: string;
  title: string;
}

/**
 * Single market index data point
 */
export interface MarketIndex {
  name: string;
  value: string;
  change: string;
  percent: string;
  direction: 'up' | 'down';
}

/**
 * Structured market dashboard data
 */
export interface MarketDashboardData {
  data_date: string;
  market_indices: MarketIndex[];
  market_volume: {
    total_volume: string;
    volume_delta: string;
    volume_trend: 'expansion' | 'contraction' | 'flat';
    capital_mood: string;
  };
  market_sentiment: {
    score: number;
    summary: string;
    trend: 'bullish' | 'bearish' | 'neutral';
  };
  capital_rotation: {
    inflow_sectors: string[];
    outflow_sectors: string[];
    rotation_logic: string;
  };
  macro_logic: {
    policy_focus: string;
    external_impact: string;
    core_verdict: string;
  };
}

/**
 * Detailed information for a single stock holding
 */
export interface HoldingItemDetailed {
  name: string;
  code: string;
  volume: number;
  costPrice: number;
  currentPrice: number;
  profit: number;
  profitRate: string;
  marketValue: number;
  horizon?: 'short' | 'medium' | 'long';
}

/**
 * Snapshot of current portfolio holdings
 */
export interface HoldingsSnapshot {
  totalAssets: number;
  positionRatio: number;
  date: string;
  holdings: HoldingItemDetailed[];
}

/**
 * Single item in a trading plan
 */
export interface PlanItem {
  id: string;
  symbol: string;
  action: 'buy' | 'sell' | 'hold' | 'monitor' | 't_trade';
  price_target: string;
  reason: string;
  status: 'pending' | 'completed' | 'skipped' | 'failed';
}

/**
 * Daily trading plan container
 */
export interface DailyTradingPlan {
  id: string;
  target_date: string;
  created_at: number;
  items: PlanItem[];
  strategy_summary: string;
}

/**
 * Data returned from a periodic performance review
 */
export interface PeriodicReviewData {
  score: number;
  market_trend: 'bull' | 'bear' | 'sideways';
  market_summary: string;
  highlight: { title: string; description: string };
  lowlight: { title: string; description: string };
  execution: {
    score: number;
    details: string;
    good_behaviors: string[];
    bad_behaviors: string[];
  };
  next_period_focus: string[];
}

export interface SectorTiering {
  sector_name: string;
  lifecycle_stage: '孵化启动' | '梯队共振' | '高潮扩散' | '末期滞涨' | '退潮回落';
  health_score: number; // 0-100
  structure_verdict: string; // 核心研判结论
  logic_audit: {
    leader_status: string; // 龙头状态描述
    follower_linkage: string; // 中军联动性
    catchup_quality: string; // 补涨质量
  };
  tiers: {
    level: 1 | 2 | 3;
    label: string; // "领涨龙头", "核心中军", "低位补涨"
    stocks: {
      name: string;
      code: string;
      status: string; // "领涨", "跟涨", "补涨启动", "炸板滞涨"
      logic: string;
    }[];
  }[];
  is_structure_broken: boolean; // 结构是否已破坏
  action_advice: string; // 操作建议
}

/**
 * Data for opportunity mining results
 */
export interface OpportunityResponse {
  policy_theme: string;
  analysis_summary: string;
  supply_chain_matrix?: {
    user_holding: string;
    opportunities: {
      stock_name: string;
      stock_code: string;
      relation_type: string;
      logic_core: string;
      policy_match: string;
    }[];
  }[];
  deployment_plan?: {
    focus_directions: {
      sector: string;
      inflow_status: string;
      logic: string;
    }[];
    top_picks: {
      name: string;
      code: string;
      sector: string;
      risk_tag: string;
      reason: string;
      buy_point: string;
    }[];
  };
}

/**
 * Data for foresight thematic日历
 */
export interface ForesightReport {
  monthly_focus: string;
  catalysts: {
    date_window: string;
    event_name: string;
    theme_label: string;
    logic_chain: string;
    opportunity_level: string;
    suggested_stocks: string[];
  }[];
  rotation_warning: string;
  macro_policy_insight: string;
}

export interface JournalEntry {
  id: string;
  timestamp: number;
  snapshot: HoldingsSnapshot;
  analysis: AnalysisResult | null;
  note?: string;
}

export interface AnalysisResult {
  content: string; 
  groundingSource?: GroundingSource[];
  timestamp: number;
  modelUsed: ModelProvider;
  isStructured?: boolean;
  market?: MarketType;
  opportunityData?: OpportunityResponse;
  foresightData?: ForesightReport;
  institutionalData?: any;
  timingData?: any;
  hotlistData?: any;
  sectorTierData?: SectorTiering;
  structuredData?: MarketDashboardData; // Resolved structured data for Market Dashboard
  periodicData?: PeriodicReviewData; // Resolved periodic review data
}

