import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult, ModelProvider, MarketType, SectorTiering } from "../types";

const sectorTierSchema = {
  type: Type.OBJECT,
  properties: {
    sector_name: { type: Type.STRING },
    lifecycle_stage: { type: Type.STRING, enum: ['孵化启动', '有序共振', '高潮扩散', '结构破坏', '末期衰退'] },
    health_score: { type: Type.NUMBER },
    structure_verdict: { type: Type.STRING },
    logic_audit: {
      type: Type.OBJECT,
      properties: {
        leader_status: { type: Type.STRING },
        follower_linkage: { type: Type.STRING },
        catchup_quality: { type: Type.STRING }
      },
      required: ["leader_status", "follower_linkage", "catchup_quality"]
    },
    tiers: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          level: { type: Type.NUMBER },
          label: { type: Type.STRING },
          stocks: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                code: { type: Type.STRING },
                status: { type: Type.STRING },
                logic: { type: Type.STRING }
              },
              required: ["name", "code", "status", "logic"]
            }
          }
        },
        required: ["level", "label", "stocks"]
      }
    },
    is_structure_broken: { type: Type.BOOLEAN },
    action_advice: { type: Type.STRING }
  },
  required: ["sector_name", "lifecycle_stage", "health_score", "structure_verdict", "tiers", "is_structure_broken", "action_advice", "logic_audit"]
};

export const fetchSectorLifecycle = async (
  sector: string,
  market: MarketType,
  apiKey: string
): Promise<AnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey });

  const prompt = `
    作为资深游资策略分析师，利用 googleSearch 深度调研当前 ${market} 市场的板块: "${sector}"。

    【核心任务：三级梯队结构审计】
    请根据以下逻辑对该板块进行拆解：
    1. **一梯队 (龙头)**: 辨识度最高、最先启动的领涨个股。
    2. **二梯队 (核心中军)**: 行业细分龙头、大市值标的。其涨幅应达到龙头的 50%-80% 才算健康。
    3. **三梯队 (补涨)**: 低位、小盘个股。行情后期看三梯队是否出现“补涨龙”。

    【结构健康研判准则】
    - **健康/延续**: 龙头连板/反包，中军紧跟，三梯队出现批量首板（热度向下扩散成功）。
    - **破坏/末期**: 龙头独涨（孤狼行情），中军跟涨无力或下跌，三梯队炸板率高且无领涨个股（扩散失败）。

    请严格按照 JSON 模式输出研判结果，包含具体的股票名单及针对“扩散是否成功”的深度定调。
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json",
      responseSchema: sectorTierSchema
    }
  });

  const parsed = JSON.parse(response.text || "{}");

  return {
    content: response.text || "",
    timestamp: Date.now(),
    modelUsed: ModelProvider.GEMINI_INTL,
    isStructured: true,
    sectorTierData: parsed,
    market
  };
};

import React, { useState, useEffect } from 'react';
import { ModelProvider, MarketType, AnalysisResult } from '../types';
import { fetchSectorLifecycle } from '../services/sectorService';
import { Layers3, Search, Loader2, Zap, AlertTriangle, TrendingUp, Info, Activity, Gauge, Timer, Sparkles, Target, ArrowRight } from 'lucide-react';

interface SectorLifecycleProps {
  currentModel: ModelProvider;
  currentMarket: MarketType;
  settings: any;
  onOpenSettings: () => void;
}

export const SectorLifecycle: React.FC<SectorLifecycleProps> = ({ currentModel, currentMarket, settings, onOpenSettings }) => {
  const [query, setQuery] = useState('');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<AnalysisResult | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [elapsed, setElapsed] = useState(0);

  useEffect(() => {
    let interval: any;
    if (loading) {
      setElapsed(0);
      interval = setInterval(() => setElapsed(prev => prev + 1), 1000);
    }
    return () => clearInterval(interval);
  }, [loading]);

  const handleAnalyze = async () => {
    if (!query) return;
    if (!settings.geminiKey) {
      onOpenSettings();
      return;
    }
    setLoading(true);
    setError(null);
    setResult(null);
    try {
      const data = await fetchSectorLifecycle(query, currentMarket, settings.geminiKey);
      setResult(data);
    } catch (err: any) {
      setError(err.message || "分析中断，请检查 API 配置。");
    } finally {
      setLoading(false);
    }
  };

  const d = result?.sectorTierData;

  return (
    <div className="space-y-6 animate-fade-in max-w-7xl mx-auto pb-20">
      {/* Header */}
      <div className="bg-white rounded-3xl shadow-sm border border-slate-200 p-8 md:p-10 relative overflow-hidden">
        <div className="relative z-10">
          <h2 className="text-3xl font-black text-slate-900 flex items-center gap-4 mb-4">
             <div className="p-3 bg-indigo-600 rounded-2xl text-white shadow-xl shadow-indigo-100">
               <Layers3 className="w-8 h-8" />
             </div>
             周期梯队研判 (Sector Tiers)
          </h2>
          <p className="text-slate-500 text-lg max-w-3xl font-medium mb-8">
            通过识别“一、二、三梯队”的博弈位置，研判板块处于热度扩散期还是末期衰竭。
          </p>

          <div className="flex flex-col md:flex-row gap-4">
             <div className="flex-1 relative">
                <input 
                  type="text" 
                  value={query}
                  onChange={e => setQuery(e.target.value)}
                  placeholder="输入板块名称，如“卫星互联网”、“半导体”..."
                  className="w-full h-16 pl-14 pr-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none font-bold text-lg transition-all"
                />
                <Search className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-400 w-6 h-6" />
             </div>
             <button 
                onClick={handleAnalyze}
                disabled={loading || !query}
                className="px-12 h-16 bg-slate-900 text-white rounded-2xl font-black shadow-xl flex items-center justify-center gap-3 transition-all active:scale-95 disabled:opacity-50"
             >
                {loading ? <Loader2 className="w-6 h-6 animate-spin" /> : <Zap className="w-6 h-6" />}
                {loading ? `全网扫描中(${elapsed}s)` : '分析板块结构'}
             </button>
          </div>
        </div>
      </div>

      {loading && (
        <div className="py-20 flex flex-col items-center justify-center bg-white rounded-3xl border border-dashed border-slate-200 animate-pulse">
           <Activity className="w-16 h-16 text-indigo-400 mb-6" />
           <p className="font-black text-slate-500 text-xl tracking-tight">AI 正在根据一、二、三梯队逻辑分析结构健康度...</p>
        </div>
      )}

      {error && (
        <div className="p-6 bg-rose-50 border border-rose-100 rounded-2xl flex items-center gap-4 text-rose-700 font-bold">
           <AlertTriangle className="w-6 h-6" /> {error}
        </div>
      )}

      {d && (
        <div className="space-y-10 animate-slide-up">
           {/* Summary Dashboard */}
           <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
              <div className="lg:col-span-1 bg-white p-8 rounded-[2.5rem] border border-slate-200 shadow-sm flex flex-col items-center justify-center text-center">
                 <div className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4 flex items-center gap-2"><Gauge className="w-4 h-4"/> 结构健康度</div>
                 <div className="relative w-36 h-36 flex items-center justify-center">
                    <svg className="w-full h-full transform -rotate-90">
                       <circle cx="72" cy="72" r="64" fill="none" stroke="#f1f5f9" strokeWidth="12" />
                       <circle 
                        cx="72" cy="72" r="64" 
                        fill="none" 
                        stroke={d.is_structure_broken ? '#ef4444' : '#4f46e5'} 
                        strokeWidth="12" 
                        strokeDasharray="402" 
                        strokeDashoffset={402 * (1 - d.health_score/100)} 
                        className="transition-all duration-1000" 
                       />
                    </svg>
                    <span className="absolute text-4xl font-black text-slate-800">{d.health_score}</span>
                 </div>
              </div>

              <div className="lg:col-span-3 bg-slate-900 rounded-[2.5rem] p-10 text-white relative overflow-hidden flex flex-col justify-center">
                 <div className="relative z-10">
                    <div className="flex items-center gap-4 mb-5">
                       <span className={`px-4 py-1.5 rounded-full text-xs font-black uppercase tracking-widest border ${
                          d.is_structure_broken ? 'bg-rose-500/10 border-rose-500 text-rose-400' : 'bg-emerald-500/10 border-emerald-500 text-emerald-400'
                       }`}>
                          {d.lifecycle_stage}
                       </span>
                       <h3 className="text-2xl font-black">{d.sector_name} · 周期定调</h3>
                    </div>
                    <p className="text-slate-300 text-xl font-bold italic leading-relaxed mb-6">
