                       </div>
                       <div className="space-y-1">
                          <div className="text-[10px] font-black text-slate-500 uppercase">中军联动</div>
                          <div className="text-sm font-bold">{d.logic_audit.follower_linkage}</div>
                       </div>
                       <div className="space-y-1">
                          <div className="text-[10px] font-black text-slate-500 uppercase">补涨质量</div>
                          <div className="text-sm font-bold">{d.logic_audit.catchup_quality}</div>
                       </div>
                    </div>
                 </div>
                 <Timer className="absolute right-[-40px] bottom-[-40px] w-80 h-80 text-white/5" />
              </div>
           </div>

           {/* Tiered Columns */}
           <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
              {d.tiers.sort((a,b)=>a.level-b.level).map((tier, idx) => (
                 <div key={idx} className={`bg-white rounded-[2rem] border border-slate-200 shadow-sm overflow-hidden flex flex-col h-full hover:shadow-xl transition-all ${
                    tier.level === 1 ? 'border-t-8 border-t-rose-500' : 
