           {/* Logic Card */}
           <div className={`p-10 rounded-[2.5rem] border-2 flex flex-col md:flex-row items-center gap-8 ${
              d.is_structure_broken ? 'bg-rose-50 border-rose-200' : 'bg-emerald-50 border-emerald-200'
